-- Housing/Human Settlements meetings — Batch 3 of 8
-- 90 rows (meetings from Human Settlements committees 91 and 291)
-- Run after: supabase_housing_batch_2.sql (if applicable)

BEGIN;

INSERT INTO meetings
    (pmg_meeting_id, committee_name, committee_id, date, title,
     summary_clean, pmg_url, num_documents)
VALUES
    (10670, 'Human Settlements, Water and Sanitation', 91, '2009-08-18', 'National Housing Code 2009 & Farm Residence Housing Programme: Departmental briefings', 'The Department of Human Settlements briefed the Committee on the new Housing Code that was currently being drafted by the Department, as prescribed by Section 4 of the Housing Act. It was in two volumes, the first dealing with the background and policy context, and the second containing the technical guidelines and the details of the Code. The core programmes were described. The Integrated Residential Development Programme aimed to provide fully subsidised, low to high income ownership, and rental housing choice options. It must establish and try to meet the needs and lifestyle choices of the communities. Beneficiaries, as distinct from past practices, would be identified only once construction had started. The Upgrading of Informal Settlement Programme aimed to address the United Nations Millennium Development Goals on improving the lives of slum dwellers, and included providing essential services such as water, sanitation and refuse collection, as well as emergency interventions, as a first step. Choices about housing options would be available in the last phase. The Social Rental Housing Programme would involve a mixture of government grants, private sector funding and equity to provide affordable rental accommodation, managed by social housing institutions. Members asked if it was still possible to make input into the Code, asked what was being done about the Social Housing Regulating Authority and suggested that the Committee must act strongly to ensure its effective functioning, queried the extent of the housing backlogs and how they would be addressed by the Code, and expressed some concern about its implementation. They also asked how the Department would publicise the Code, if the programmes were budgeted for, whether the Prevention of Illegal Eviction and Unlawful Occupation of Land Act favoured the tenant or landlord, what was done to address the situation where registered beneficiaries could not be found, and what the Department was doing about influx of', 'https://pmg.org.za/committee-meeting/10670/', 0),
    (10703, 'Human Settlements, Water and Sanitation', 91, '2009-08-25', 'Social rental housing benefits: research & study briefing by Social Housing Foundation', 'The Committee received a briefing from the Social Housing Foundation on a report commissioned and undertaken in the past year, in conjunction with the Department of Human Settlements, around social rental housing, its supply and demand, utilities and municipal charges, backyard and informal rentals and evictions. This had produced enough information to enable a comparison between social rental housing (SRH) and the Reconstruction and Development Programme (RDP) housing, done according to a cost benefit analysis. A full report would be launched during September, which would start a wider debate around housing issues. The report had isolated the hidden costs, had looked to the broader economic impact and ongoing costs to government and society of both schemes. It produced a longer-term view, as opposed to the current debates that tended to focus on short-term benefits, but had of necessity been limited in its approach. The study concluded that neither model could be chosen as applying across the board, as each was effective in different circumstances. SRH was well-suited to densification, but was not an option for the very poor, as it cost about R1 500 per month. In answer to questions from Members, it was also said that improving the location of RDP housing could do much to improve its viability. Members were concerned that the current recession might have skewed the data, stated that they had expected broader results, and pointed out that many of the hidden costs were those supposedly borne by municipalities, but that in fact the municipalities were not spending money on service delivery or maintenance. A number of questions isolated the problem that those occupying RDP houses did not see them as an asset, because they were not widely sought after for resale, because there were also restrictions on resale within a certain time, and because they could not afford the maintenance, which was worsened by the poor quality of the houses. Members asked if enough had been do', 'https://pmg.org.za/committee-meeting/10703/', 0),
    (10746, 'Human Settlements, Water and Sanitation', 91, '2009-09-01', 'Department''s failure to attend meeting deliberations & adoption of Committee Minutes', 'The Department of Human Settlement was due to brief the Committee on regulations for the Housing Development Agency and the Social Housing Regulatory Authority. They advised the Committee at short notice that they were not ready to present this briefing and failed to send a delegation. The Members condemned this action and resolved to reprimand the Department. The Minister would be informed on what had happened. Members made changes and then adopted the minutes of two earlier meetings.', 'https://pmg.org.za/committee-meeting/10746/', 0),
    (10823, 'Human Settlements, Water and Sanitation', 91, '2009-09-15', 'Agrément South Africa: advantages and benefits for sustainable housing', 'The Committee was briefed by Agrément South Africa on novel building products and their application in building sustainable housing. The Committee expressed interest and hope at the possibility of these products being utilised. The Committee took the Department of Human Settlements firmly to task for not using these materials and methods in sustainable housing projects. Members were distressed that housing projects, most notably the N2 Gateway Housing Project, were not enrolled with the NHBRC to ensure standards were upheld in government housing projects and asked the Department to account for this.', 'https://pmg.org.za/committee-meeting/10823/', 0),
    (10886, 'Human Settlements, Water and Sanitation', 91, '2009-10-13', 'Department of Human Settlement Annual Report 2008/2009: briefing', 'The Department of Housing briefed the Committee on its 2008/09 Annual Report. The Department’s operations were split into four main programmes and each of those programmes was described both in terms of their scope and the achievements during the year. Most of the budget was directed towards housing development finance and there was a net increase of 1.7 billion in funding between the previous year and the year under review. All programmes performed well ranging from 97% use of funds to 100%. The Department informed the committee that the system of auditing performance for 2009/2010 will be done in the same manner as financial statements were conducted. The Auditor-General’s municipal audit report showed that between 1994-2004, 6 905 municipal officials had unlawfully received low income houses. Out of this, 2 585 files had already been handed over to the Special Investigations Unit (SIU) for investigation. Extensive engagements were undertaken with provincial housing departments, municipalities and implementation agents, to assist with delivery on their respective mandates in respect of National priority projects. Agreements of cooperation between the three spheres of government were concluded for the Klarinet Housing Project and the Khutsong Redevelopment Initiative. Implementation agreements were being finalised among the executive principals of administration of the three spheres of government for the Kalahari Housing Project, the Khutsong Redevelopment Initiative and the Lerato Park Housing Project. 4000 subsidised housing units were handed over to beneficiaries of the N2 Gateway Housing Project and the partnership between government and the banking sector enabled the construction of bonded housing units for mixed-income households with the emphasis on sustainability. Members were pleased to hear of the unqualified audit report but emphasised the need for better implementation of programmes within the Department. They also advised the Department to improve its ', 'https://pmg.org.za/committee-meeting/10886/', 0),
    (10905, 'Human Settlements, Water and Sanitation', 91, '2009-10-15', 'National Housing Finance Corporation & National Urban Reconstruction Agency Annual Reports 2008/09', 'National Urban Reconstruction Agency (NURCHA) presented on its financial performance for the year 2008/2009. It outlined its strong funding partnerships with the Soros Economic Development Foundation (SEDF) and other financial institutions. The organisation had a unique capital structure with elements of both commercial funding and grants and had become specialised in construction finance and its inherent risks. It provided various products in the form of bridging finance for housing and residential community infrastructure, as well as intermediary services that worked with contractors and developers. It had had a positive year with regard to its core business of construction finance. The company showed increased housing loans approval, despite the negative economic environment, and also showed healthy financial statements, with its profits of R 49 million being generated through money market investments, while R53 million reflected income earned on interest and fees on projects that formed NURCHA’s core business. Members asked questions on the difference between the figures for approved housing loans and completed houses, asked how NURCHA was dealing with the global economic meltdown and how this would affect its budget for the following year. Members asked about the criteria used to select contractors and developers who were to be given financial assistance, and were concerned with the limited numbers of females in the construction industry. They also asked about the footprint in certain provinces, the training provided, and whether this was limited only to Gauteng, and asked about unblocking of stalled projects. National Housing Finance Corporation (NHFC) then presented its Annual Report 2008/09, and described the changes that the economic environment had assumed since the beginning of the economic meltdown in 2008. The NHFC also reported an increased risk in the markets from both its financial instruments, as well as the risk of loan defaults by the end users in', 'https://pmg.org.za/committee-meeting/10905/', 0),
    (10933, 'Human Settlements, Water and Sanitation', 91, '2009-10-20', 'Social Housing Foundation, Rural Housing Loan Foundation; National Home Builders Registration Council Annual Reports 2008/09; Committee Report on Eastern Cape oversight visit', 'The Committee heard presentations from three organisations actively involve in the housing industry on their annual reports to the Committee. It emerged that the downturn in the economy had affected all of these organisations. Concern was also raised by members about the quality of houses built in some of their projects. The Committee questioned whether the NHBRC had teeth as on their site visit, they had noticed that the NHBRC inspectors had made certain recommendations, but contractors had not done anything about these. The Committee was concerned that the Social Housing Foundation, due to close on 31 March 2010, was not currently actively involved in the establishment of the Social Housing Regulator Authority .', 'https://pmg.org.za/committee-meeting/10933/', 0),
    (10983, 'Human Settlements, Water and Sanitation', 91, '2009-10-27', 'Department of Human Settlements on the Diepsloot and Harry Gwala informal settlements', 'The Minister had visited the Diepsloot informal settlement in August 2009 and was appalled by the living conditions of the residents living in the settlement. The Gauteng Department of Local Government and Housing planned to relocate approximately 10 000 families from the existing informal settlement in Diepsloot West to a newly acquired site in Diepsloot East. The 80 ha site had been purchased for R60 million. This was a discounted price, granted on condition that the current landowner was the appointed the developer of the site. The landowner was a registered developer. The budgeted cost for the development was R200 million but costs were expected to escalate over the three-year term of the development. Planning was under way and the development of the first phase would commence in the 2011/12 financial year. The second phase was planned for 2012/13 but there was an environmental issue and a bullfrog colony would have to be relocated before the land could be developed. The Harry Gwala informal settlement at Rietfontein, near the town of Benoni in the Ekhuruleni Municipality was situated in an area fount to be unsuitable for human settlement. An alternative site was identified and was being developed but residents were reluctant to be relocated to the new site, which was 25 km away. Residents had brought a court case against the Ekhuruleni Municipality to demand that water, sanitation and refuse removal service were provided in the settlement. Residents also demanded high-mast lighting of the area at night. The Municipality was instructed by the Court to provide water and sanitation services but the other demands were dismissed. The case had gone to the Constitutional Court on appeal. The Constitutional Court Judges ruled that the MEC, the Minister of Human Settlements and the Director-General of the Department of Human Settlements were added as respondents. Judgement in the case was pending. Members were concerned over the purchase agreement with the Diepsloot Eas', 'https://pmg.org.za/committee-meeting/10983/', 0),
    (11012, 'Human Settlements, Water and Sanitation', 91, '2009-11-02', 'Committee Report on Oversight Visit to the Eastern Cape', 'The Committee briefly considered the report on its oversight visit to the Eastern Cape . Members were generally happy with the content of the report and confined their discussion on the recommendations contained in it. The Committee stated that there was a great need to develop a national policy that would coordinate and manage the beneficiary list. They also expressed concern about the houses that were unfinished but were given to beneficiaries. They recommended that houses should only be given when they were finished and had all the basic services such as water and electricity. They felt that the oversight report raised many critical issues that government need to pay attention to and therefore the report need to be made known to parliament and the public at large.', 'https://pmg.org.za/committee-meeting/11012/', 0),
    (11040, 'Human Settlements, Water and Sanitation', 91, '2009-11-03', 'Housing Beneficiary List Review Plan, Implementation of Joe Slovo Constitutional Court Judgement: Progress Report', 'The Department briefed the Committee on the Beneficiary List Review Plan, noting that municipalities did not have capacity to effectively execute the responsibility of compiling beneficiary lists. The programme that would be introduced by the Department aimed at addressing some of the challenges and gaps that government faced with the beneficiary list process. During the implementation of the strategy, a housing needs survey would be established and a municipality would ensure that the particulars of all the persons identified during the survey were recorded on the National Housing Needs Register. However the Committee was not happy with the fact that private service providers would compile the list. The Department defended its decision by saying that the people employed by the service providers came from the communities that they served and that such service providers would be more effective in compiling the beneficiary list. The Department then took the Committee through its Progress Report on the implementation of the judgement of the Constitutional Court case: Residents of Joe Slovo Community Western Cape v Thubelisha Homes and Others Case No CCT 22/08. Most of the questions raised in the meeting were not answered, as the Committee and the Department felt that a workshop was necessary to address the matters raised.', 'https://pmg.org.za/committee-meeting/11040/', 0),
    (11072, 'Human Settlements, Water and Sanitation', 91, '2009-11-10', 'Department of Human Settlements on the Medium Term Budget Policy Statement (MTBPS)', 'The Acting Director-General of the Department of Human Settlements briefed the Committee on the Medium Term Policy Statement for the period 2010 to 2013. No major new allocations or reductions were envisaged for the adjusted medium term budget. The Department replaced the previous Department of Housing and was currently engaged in formulating strategic plans for the net five years. The provision of housing remained the major area of responsibility and the Department needed to maintain and accelerate housing delivery within the context of the development of the broader community. The key factor was the coordination and alignment of all the entities involved in the provision of housing and the development of communities. The Department was in the process of reviewing the funding structures and identifying the key service delivery priorities. An analysis of the national, provincial and municipal plans, policies, programmes and grants had been undertaken and a coordinated plan would become available in March 2010. The Department planned to strengthen the monitoring of the housing grants allocated to the provinces. The original budget allocation for 2008/09 was R10.6 billion. A mid-year adjustment increased the total allocation to R10.928 billion, of which R8 million was not spent. As at 30 th September 2009, the Department had spent 56% of the budget and was slightly behind schedule. The Department did not anticipate overspending during the remainder of the year and was managing the under-spending of the allocated funds. The funding requirement was expected to increase from R12.6 billion to R15 billion in 2010, R17 billion in 2011 and R19 billion in 2012. The Department had developed funding proposals for the capitalisation of housing institutions, priority projects, the enhancement of capacity within the Department, bulk infrastructure projects in key areas and land acquisition (particularly in urban areas.) Members asked questions about the responsible party that woul', 'https://pmg.org.za/committee-meeting/11072/', 0),
    (11141, 'Human Settlements, Water and Sanitation', 91, '2009-12-01', 'Human Settlements December Workshop: Day 1', 'The Department of Human Settlements (the Department) responded to the Committee’s request for more detailed interaction by hosting a two day workshop. The session was aimed at improving the Committee’s understanding of the basis for the decisions made in the programmes of the Department. It was also aimed at providing a platform for the Department to hear Members’ views. The Members’ inputs would be recorded and compiled into a report to provide guidance for the development of the Department’s programmes. The Committee heard four presentations in the first session: Human Settlements Conditions, Appreciating the Scope of the Human Settlements Mandate, the Spatial/ Urban Background and Context and the Sector Strategy for 2009-2014. A major theme of the presentations was the rapid and irreversible urbanisation and migration in South Africa, coupled with growth in informal settlements, lack of access to basic services, unbalanced property markets and poor planning in the past. All future planning must be put into context. There were widely divergent housing situations, and statistics were given of the outstanding need for services. South Africa was further characterised by structural unemployment and informality, with many households falling into the subsidy income band. The Department acknowledged that different settings required different interventions, and also recognised that much of the current housing was not well located, but that many people were unable to move closer to their work. The population was densifying in those urban areas that had always been major cities, and no new economic centres had emerged over the past forty years. Choices had to be made about South Africa''s urban future, which also take into account degradation of land, the effect of climate change and the unused agricultural land. The Department then described its expanded mandate, the importance of integrating elements, explained human settlement development principles, and set out the vario', 'https://pmg.org.za/committee-meeting/11141/', 0),
    (11142, 'Human Settlements, Water and Sanitation', 91, '2009-12-02', 'Human Settlements Workshop Day 2: Inclusionary Housing Policy, Accreditation of Municipalities, Urban Sprawl', 'The second day of the Department''s workshop dealt with: ▪ the accreditation of municipalities to administer national and provincial housing programmes; ▪the role of the Department in the management of service providers; ▪an overview of the current inclusionary housing policy and its development; and ▪how to manage urban sprawl while giving effect to the delivery of human settlements. ▪ The accreditation of municipalities The Director: Intergovernmental Relations provided key definitions of the concept of accreditation and delegation and referred to the relevant legislative framework. The Committee was informed of the rationale behind accreditation and the principles on which the policy was developed. The Department''s overall approach to accreditation as well as the institutional, funding, systems and capacity arrangements and ongoing monitoring requirements and implementation arrangements were presented. The Committee discussed the rationale behind accreditation and the capacity of municipalities to undertake their accredited or delegated responsibilities and their demonstrated fund management capacity. Several members including the Committee Chairperson were particularly irked by the disjuncture between reports of progress and the actual condition of housing projects on the ground, which were often found to be in a shocking state. ▪ The role of the Department in the management of service providers The Chief Director: Financial Services provided an overview of this. The Committee was interested in how the Department had addressed complaints about delays in payments to service providers by the State and how they were implementing the President''s call to conclude such payments within a period of thirty days. The Committee also discussed the issue of black-listed companies and the impact this had in slowing down the process of vetting prospective service providers. ▪ An overview of the current inclusionary housing policy and its development. The intention of the policy', 'https://pmg.org.za/committee-meeting/11142/', 0),
    (11716, 'Human Settlements, Water and Sanitation', 91, '2010-01-27', 'Briefing by the Minister of Human Settlements on his visit to N2 gateway project in 2009, decisions taken, resolutions made as well as timeframes set', 'Minister Tokyo Sexwale briefed the Committee with specific mention of the N2 Gateway Project. He said that the intention was to create sustainable human settlements. So far 2.8 million housing opportunities had been created; 2.3 million houses had been delivered but that 40 000 of these were going to be demolished or rectified as they were badly built. Contractors had, in the past, taken advantage of government with shoddy workmanship and the use of inferior materials. There were a few good BEE companies but many were bad. The 40 000, when compared to the 2.3 million houses delivered, were considered a drop in the ocean. Ten percent of the Department’s budget of R1.3 billion would be used to rectify the 40 000 houses. Corrupt persons responsible for the inferior houses would be brought to book. Corruption was present in government at national and provincial as well as local government level. The N2 Gateway Project had broken new ground and was a pilot project. However, it only had a 5% rent collection rate. There were structural defects and there was a lack of general maintenance. The Emerald Sky Project at Buffalo City however had a 96% rent collection rate. The N2 Gateway Project was in Phase 1 and plans were in place to address problems. An integrated approach was needed and he would work closely with the Western Cape Premier, Ms Helen Zille. He also hoped that the Mayor of Cape Town, Mr Dan Plato, could become more involved. Projects were visited in order to keep track of where and how funds were being spent. Government was currently involved in 7994 projects. This was the Committee’s first interaction with the Minister. The government’s figure of 2.3 million houses was questioned. Minister Sexwale agreed to have the correctness of the figures checked. Members were concerned about the N2 Gateway rental collection rate of 5%. The question was whether tenants are able to afford the rentals or whether they were simply not paying? Housing delivery had been plagued w', 'https://pmg.org.za/committee-meeting/11716/', 0),
    (11147, 'Human Settlements, Water and Sanitation', 91, '2010-01-27', 'Minister of Human Settlements on his visit to N2 Gateway Project and other housing projects', 'Minister Tokyo Sexwale briefed the Committee with specific mention of the N2 Gateway Project. He said that the intention was to create sustainable human settlements. So far 2.8 million housing opportunities had been created; 2.3 million houses had been delivered but that 40 000 of these were going to be demolished or rectified as they were badly built. Contractors had, in the past, taken advantage of government with shoddy workmanship and the use of inferior materials. There were a few good BEE companies but many were bad. The 40 000, when compared to the 2.3 million houses delivered, were considered a drop in the ocean. Ten percent of the Department’s budget of R1.3 billion would be used to rectify the 40 000 houses. Corrupt persons responsible for the inferior houses would be brought to book. Corruption was present in government at national and provincial as well as local government level. The N2 Gateway Project had broken new ground and was a pilot project. However, it only had a 5% rent collection rate. There were structural defects and there was a lack of general maintenance. The Emerald Sky Project at Buffalo City however had a 96% rent collection rate. The N2 Gateway Project was in Phase 1 and plans were in place to address problems. An integrated approach was needed and he would work closely with the Western Cape Premier, Ms Helen Zille. He also hoped that the Mayor of Cape Town, Mr Dan Plato, could become more involved. Projects were visited in order to keep track of where and how funds were being spent. Government was currently involved in 7994 projects. This was the Committee’s first interaction with the Minister. The government’s figure of 2.3 million houses was questioned. Minister Sexwale agreed to have the correctness of the figures checked. Members were concerned about the N2 Gateway rental collection rate of 5%. The question was whether tenants are able to afford the rentals or whether they were simply not paying? Housing delivery had been plagued w', 'https://pmg.org.za/committee-meeting/11147/', 0),
    (11241, 'Human Settlements, Water and Sanitation', 91, '2010-02-23', 'South African Housing Co-operatives: briefing by SA Housing Co-operatives Association ', 'The National Chairperson of the South African Housing Co-operative Association briefed the Committee on the concept of co-operative housing, and the experiences on the ground. He explained the concept of different housing models and highlighted the main principles of co-operatives, and their advantages over the rental social housing or sectional title schemes. Co-operative housing envisaged that a group of people, who shared a common need for housing, would pool their money, their skills, and their time, and would set up and register a co-operative, which was a legal entity. They then negotiated for land and good prices on building materials and they built houses collectively. In this type of co-operative the unemployed could be accommodated, because they would qualify for a government subsidy, and the rest of their contribution would be in “sweat equity” by working in the construction team. The advantages of this model were that the beneficiaries were actively involved in every stage of the development of the project and thus they would be happy with the end result. They worked actively for their houses and did not receive them passively. Such a model also created jobs, training opportunities that could subsequently use the skills to help others, and could also encompass other service jobs in the community, such as childcare. In particular it was suited for development opportunities for youth. This development type of co-operative mostly operated in the township and rural areas. SAHCA outlined that a continuous housing co-operative mostly operated in the inner cities, in large blocks of flats, where working, but low-earning people, might pool their funds to register a co-operative, collectively purchase a high-rise building, elect a Board of Directors who would then manage the finances as well as maintenance of the building, and where each co-operative member would own a unit in the block, for which a share certificate was given. If the member left the building, th', 'https://pmg.org.za/committee-meeting/11241/', 0),
    (11279, 'Human Settlements, Water and Sanitation', 91, '2010-03-02', 'Housing Development Agency: Progress report; & International agreement process briefing ', 'The Housing Development Agency (HDA) briefed the Committee on its progress since its establishment in April 2009. The objectives of the HDA translated into three core functions of land assembly, project delivery support services to organs of states such as provinces and municipalities, and monitoring and facilitation. The HDA was to make landed properties available, and promote the development of sustainable human settlements and communities on land. The HDA would consult with the Minister, as well as provinces and municipalities, to finalise the details of its mandate by the end of March 2010. Funding remained a major challenge. In the first budget, no provision had been made for working capital, and the money made available by Parliament was restricted to acquiring land. It had, however, managed to progress its institutional development quite far, by developing a macro-organisational structure, and would be filling five of the 15 vacant posts on 1 March, and one on 1 April, with the remainder to be filled during 2010. There was high emphasis on employment of competent staff. The Governing Board was appointed by the Minister, was the accounting authority, and had met six times to approve governance documents. It had good working relationships with stakeholders. Intergovernmental Protocol agreements were in place, but political or legal finalisation was in some cases still pending. Other projects were outlined. There was a business model around Land Acquisitions Management and HDA was in consultation with Servcon and Transnet regarding their property portfolios. Government-to government land transactions were a prominent issue. Members stressed that it would be important to assess issues on the ground, despite the fact that the presentations looked good. Members were concerned about the continuing backlogs and asked how these would be addressed , questioned whether the Millennium Development Goals would be attainable, asked about time frames and planning, and asked ', 'https://pmg.org.za/committee-meeting/11279/', 0),
    (11292, 'Human Settlements, Water and Sanitation', 91, '2010-03-04', 'Department of Human Settlements Strategic Plan 2009 to 2014', 'The Department of Human Settlements briefed the Committee on the key aspects that came out of the Strategic Plan for 2009-2014, and also reflected on some aspects emanating from the State of the Nation Address. He noted that the Department now had an increased mandate, dealing also with Sanitation in terms of the Water Services Act of 1998. This emphasised rural deficiencies with regard to sanitation. The Department also outlined the proposed legislation and new planned regulations and guidelines which included the (New) National Housing Code, Guidelines for Human Settlement Planning and Design (Red Book), and Guidelines for Environmentally Efficient Low Cost Housing. The Department gave a strategic overview of the sector. A key feature was the rapid urbanisation and migration from urban areas, with population growth, household patterns and the impact of unemployment. The difference between formal, information and farm settlements was outlined, as well as some of the problems with having to remove large amounts of soil and rubble from some areas before being able to develop. Challenges to basic services, and current needs, were set out. Some households maintained a dual residency approach, but the urbanisation was irreversible and growing. The Service Delivery priorities included upgrading well located informal settlements, and providing proper services and land tenure to 500 000 households by 2014. The Department aimed to increase the rate of affordable rental housing delivery of at least 20 000 units per year. It planned to set aside 6 250 hectares of well located public land for low income and affordable housing (accommodating approximately 400 000 units by 2014). It would accelerate provision and upgrading of bulk infrastructure networks to prioritised settlements by 2014, and would accommodate people whose salaries were too high to get government subsidies, but earned too little to qualify for a normal bank mortgage. It would also involve other departments in t', 'https://pmg.org.za/committee-meeting/11292/', 0),
    (11314, 'Human Settlements, Water and Sanitation', 91, '2010-03-09', 'Department of Human Settlements on Budget Vote 30; National Treasury on Budget Aspects relating to Human Settlements', 'The Acting Director-General of the Department of Human Settlements briefed the Committee on the Department’s major goals and challenges and the budget for the Medium Term Expenditure Framework period 2010/11 to 20112/13. The Department highlighted a marked increase in urban populations as a result of migration from rural areas. In some cases, people had acquired housing units in both urban and rural centers. This increase in urban settlement resulted in an increase in the number of informal settlements. The informal settlements compromised access to basic services and were a challenge to the Department, which was tasked with creating sustainable and suitable human settlements. The Department illustrated the untenable nature of informal settlements. The land on which informal settlements were erected generally did not belong to the inhabitants, which created insecurity of tenure as the land was subjected to reclamation by Government. The Department set out its proposals to improve housing and service delivery. The Department outlined the key focus areas that would guide policy for the following fiscal year. The major goals were the provision of housing for 500 000 people by 2014, acquiring low-cost Government-owned land for human settlement and generally improving service delivery with regard to housing. The Department planned to implement and enforce service level agreements with the service providers in the housing sector. Members asked about the sanitation program highlighted in the presentation and the funding allocation for the program. They were concerned about the slow pace of replacing the bucket system with water-borne sewerage systems, particularly in rural areas. Members asked about the solution for accommodating individuals who were not poor enough to benefit from the housing programme but who were not wealthy enough to gain access to bank loans to purchase homes due to a lack of collateral. Members queried the unannounced shift in policy from the total e', 'https://pmg.org.za/committee-meeting/11314/', 0),
    (11366, 'Human Settlements, Water and Sanitation', 91, '2010-03-16', 'Human Settlements Portfolio Committee: Planning for Budget Vote hearings', 'The Committee considered and adopted the minutes of previous meetings. In addition, the Committee briefly discussed their planned budget vote hearings with the Department of Human Settlements.', 'https://pmg.org.za/committee-meeting/11366/', 0),
    (11403, 'Human Settlements, Water and Sanitation', 91, '2010-03-23', 'Human settlements'' stakeholders & insititutions; Budget: Financial Fiscal Commission (FFC)', 'The Committee was briefed by the Financial Fiscal Commission (FFC) on the implementation of the recommendations made by the Commission concerning the division of revenue for human settlements. Members raised questions around the capacity to implement certain recommendations, particularly the integration of funding with regard to the Municipal Infrastructure Grant (MIG). Questions were asked concerning the capacity of municipalities and the delays in the accreditation of municipalities. The Committee was briefed by Statistics South Africa (StatsSA) on the progress made in housing delivery since 1996. The most significant factor was the pattern of inter-provincial migration detected in recent years. The most recent statistical data were obtained from a survey conducted in 2007, which excluded accurate data on the number of migrants from neighbouring countries. A census was planned for 2011, which would provide more accurate data. Members welcomed the information provided that could be used by the Committee to gauge progress. The Rural Housing Loan Fund (RHLF) presentation outlined the progress made and the projected performance for the coming financial year. Members were concerned that the use of intermediaries resulted in low-income borrowers being charged extremely high interest rates on housing loans. The National Home Builders Registration Council (NHBRC) provided a high level overview of the NHBRC’s function as a short term warranty provider for structural defects in housing units. Issues around enrolment via provincial housing departments were raised in light of the NHBRC’s stance against providing warranty services for housing units and projects that were not enrolled. Members were very concerned over the non-compliance of the provincial housing authorities with the legislation on enrolment and the failure of the provincial Departments of Housing to pay the required fees over to the NHBRC. Questions concerning the outsourcing of housing construction inspections', 'https://pmg.org.za/committee-meeting/11403/', 0),
    (11411, 'Human Settlements, Water and Sanitation', 91, '2010-03-24', 'Human Settlements budget: public hearings: day 1', 'The Department of Human Settlements had built 89 522 houses in the North West during the last five years. In Rustenburg 458 houses were completed by the end of February and for the rest of the province it was 1960. The increase in the cost of building units had decreased in the North West due to the cost of building materials. The Department was allocated with a budget of R1.1 billion and to date R1.093 billion had been spent. The target for the next five years was to deliver 70 000 units. There was a gradual decline in the number of units that would be delivered; this was because the Department was focusing on quality rather than quantity. The conditional grant for the next financial year was R1.22 billion. Vacant posts were being filled and an audit and reconciliation unit had been established in order to address the audits for the Auditor-General. Some of the major projects for 2009/10 for the Northern Cape were Accreditation, Consolidation Emergency and Rural Development. During the past financial year 4089 Units had been built. The KZN provincial department would focus on middle income property intervention. The province sought to enhance effective service delivery and was aligning itself with the strategic objectives of the government at national level. Most of the budget for the 2010/11 would go towards rural development, the target for the same financial year was to build 25 000 houses. For the first time in the history of the province of the Free State, 100% of its funds had been spent. Of the R1.015 billion allocated to the Department, R1.011 billion had been spent. Fraud was one of the biggest challenges facing the department. South African Housing Co-operative Association (SAHCA) wanted to work closely with the Department of Human Settlements, as there was tremendous benefit in this, as highlighted by the Presidency. SAHCA had pilot housing projects in the country and wanted the department to incorporate these into their departmental programmes. The Depa', 'https://pmg.org.za/committee-meeting/11411/', 0),
    (11413, 'Human Settlements, Water and Sanitation', 91, '2010-03-25', 'Human Settlement budget: public hearings: day 2', 'The Committee heard submissions from the National Treasury, Ms Sylvia Hammond (private submission) and the Department of Human Settlements on the budget vote for housing. The Director: Transport and Housing of the National Treasury presented a broad overview on the Housing Budget Vote 30 in the 2010/11 Budget. The National Treasury had increased the amount of funding made available for the Medium Term Expenditure Framework period 2010/11 to 2012/13. An additional amount of R1 billion was made available for the 2012/13 fiscal year, increasing the funds made available for housing to R17.9 billion. The transfer of the responsibility for water and sanitation services from the Department of Water Affairs and Forestry to the Department of Human Settlements made an additional R1.2 billion available for the provision of sanitation services in rural areas. The additional funding for sanitation would be added to the grants payable to Local Government (municipal) authorities over the following three years. An amount of R1 billion was made available by the National Treasury to address the issues concerning the housing gap market. No formal policy on the application of the funds had been formulated as yet. The briefing included an overview of the various issues and the different options under consideration. The National Treasury was concerned over the low quality of the houses being built and the limited number of housing units being registered with the National Home Builders Registration Council. The lists of beneficiaries awaiting housing should be transparent and the process should be free of any corruption. Members were concerned about the greater emphasis on rectification programmes in provincial budgets, providing additional funding to municipalities for sanitation services, the doubtful benefit of introducing standard contracts for contractors, the doubtful ability of the grantee scheme to prevent people from losing their homes, the non-enrolment of houses and the money o', 'https://pmg.org.za/committee-meeting/11413/', 0),
    (11461, 'Human Settlements, Water and Sanitation', 91, '2010-04-13', 'Oversight Report of visit to the Western Cape', 'The Committee briefly discussed its Report on the Department of Human Settlements budget for the 2010/2011 financial year. The Committee had requested that there should be an alignment between the Department and the President’s State of the Nation Address. The adoption of the report was postponed to the next day. In addition, Members considered the Committee’s Oversight Report to the Western Cape. They questioned why the unfinished and dangerously built houses in Beaufort West and Mossel Bay were not mentioned in the Report. They recommended that Mossel Bay had to be monitored quarterly (concerning its challenges) and that the land Report in Knysna be forwarded to the Minister of Human Settlement, Mr Tokyo Sexwale. The report was duly adopted with amendments. Finally, the Committee also approved outstanding minutes as well as its programme for the second-term.', 'https://pmg.org.za/committee-meeting/11461/', 0),
    (11553, 'Human Settlements, Water and Sanitation', 91, '2010-05-04', 'Portfolio Committee Human Settlements Committee Programme for Third and Fourth Terms', 'The scheduled report back from the Department of Human Settlement on various recommendations made by the Committee was postponed due to capacity constraints and other challenges experienced by the Department. Members expressed concern about the Department’s non-performance, noting that it had a negative effect on the Committee''s ability to move from the planning stage and focus on delivery. It was decided that the Committee would arrange a strategic planning session with the new Director-General in order to share its frustrations about the present state of the Department. Members considered and adopted its programme for the remainder of the year as well as the minutes of previous meetings.', 'https://pmg.org.za/committee-meeting/11553/', 0),
    (11650, 'Human Settlements, Water and Sanitation', 91, '2010-05-25', 'Public Service Commission Monitoring & Evaluation report on Department of Human Settlements; Nutec Advanced Technology House Building; Issuing of Title Deeds', 'The Public Service Commission presented its monitoring and evaluation report on the Department, using the nine principles of good governance found in the Constitution. The Commission had presented the report to the Department on 25 January together with a list of recommendations, which the Department had six months to implement. This was its second assessment of the Department, the first being in 2001/2. The Department had scored well moving from 58% in 2001/02 to 76% for 2009/10. Members questioned why there was a ten-year gap between assessments. They wanted to know if the process was based on paperwork or on actual implementation. They asked what responsibility the Department had over the provincial government? Several members commented that there was a big difference between what was practically experienced on the ground and what appeared on paper. The disjuncture between national and provincial was commented on. Group 5 / Everite gave a presentation on alternative housing technologies. They had a dedicated housing division with an alternative building technologies unit. This type of construction gave the advantages of being faster to build at a lower price with better thermal and acoustic insulation properties. They were willing to put up structures for emergency housing, after a fire for example, to help overcome the mindset of people, which was against these types of houses. Members wondered how they could change the mindset of the people who thought that if a house was not made of brick and mortar, it was a temporary structure. They asked questions on the house’s strength, durability, looks, cost, and whether it could stand up to earthquakes and other natural hazards. They asked whether it would retain its investment value. The Department gave a briefing on the issuing of title deeds to state-subsidised homeowners. The registration, transfer and ownership of title deeds of state housing subsidies were the last step of the state housing process. Title deeds w', 'https://pmg.org.za/committee-meeting/11650/', 0),
    (11698, 'Human Settlements, Water and Sanitation', 91, '2010-06-01', 'Eastern Cape Department of Human Settlements Intervention Close-Out Report; Harry Gwala Informal Settlements; Report on North West Housing Corporation; and Joe Slovo Constitutional Court Progress Report: Department of Human Settlements: Briefing on progre', 'The Department of Human Settlements briefed the Committee on the Eastern Cape Intervention Close-out Report, the outcome of the Harry Gwala Informal Settlements Constitutional Court Case, the winding up of the North West Housing Corporation, and the progress report on the Implementation of the Judgement of the Constitutional Court in respect of Joe Slovo Informal Settlement. The Scottsdene Self Help Scheme and the Housing Development Agency’s presentation on funding were postponed at the request of the Department. The Eastern Cape Intervention Close-out Report recorded the Department’s intervention in April 2008 in response to the serious decline in housing delivery in the Eastern Cape from the 2004/05 financial year onwards. Over a three year period the Eastern Cape had lost R1 billion due to non-expenditure. A team of officials and professionals had been deployed to the Eastern Cape and a turnaround strategy had been adopted. An important component was the rectification of poor and substandard housing and the unblocking of blocked projects. Rural Housing development was problematic due to a lack of infrastructure and capacity was a problem throughout the province. Positive results had been demonstrated in the 2009/10 financial year. The Committee had undertaken an oversight visit to the Eastern Cape and had made recommendations to the Department. Members were concerned that there were inconsistencies in the statistics provided by the Department and that there was no clear indication of how many houses had been rectified. A Member of the Congress of the People expressed her concern about the poor quality of the houses, the high number of abandoned and incomplete projects, and low capacity in the rural areas. The Department briefed the Committee on the Constitutional Court ’s judgement of 19 November 2009 dismissing the appeal by the residents of Harry Gwala Informal Settlement. The Member of the Executive Council for Human Settlements, Gauteng , was ordered to take', 'https://pmg.org.za/committee-meeting/11698/', 0),
    (11755, 'Human Settlements, Water and Sanitation', 91, '2010-07-27', 'Money Bills Amendment Procedure & Related Matters Act Workshop, Home Loan Mortgage Disclosure Act & Beneficiary Occupancy Audit: Department''s Reports ', 'The Parliamentary Committee Section gave a presentation on the Money Bills Amendment Procedure and Related Matters Act (the Act) , noting the definition of a money bill, the objectives of the Act, and the establishment of the Parliamentary Budget Office (PBO) and various committees for the consideration of money bills. The powers and functions of National Assembly and National Council of Provinces finance committees were outlined, as well as the function of the portfolio committees, and in particular the necessity for these committees to make detailed and accurate reports, which would require that they receive support on the budget process. The prescribed dates and procedures in terms of the Act were outlined. The function and requirements of the Budget Review and Recommendations Reports (BRRR), the Medium Term Budget Policy Statement (MTBPS) and the National Annual Budget were outlined. Members asked what amendments could be suggested by committees, whether there was room for moving budget allocations from one department to another, whether there was sufficient oversight in respect of quarterly reports, and whether there was sufficient link established between spending and achieving appropriate outcomes. Members asked if the Minister of Finance could ignore the recommendations of Parliament, what role would be played by the NCOP, and commented that certain priorities in one area might put strain upon priorities in other areas. They felt it was necessary to re-orientate committees, and wondered if the legislature had sufficient resources to implement the Act fully, and also commented that the Parliamentary Research Unit should ideally undertake its own field research rather than relying on information from departments themselves. Members sought clarity on the time frames, asked if the Annual Report of the Department had yet been tabled, and noted that a workshop would be held on the proposed template if this was accepted by the House. The National Department on Huma', 'https://pmg.org.za/committee-meeting/11755/', 0),
    (11806, 'Human Settlements, Water and Sanitation', 91, '2010-08-10', 'Sanitation Programme progress and Beneficiary List Management update: briefing by Department of Human Settlements', 'The Chief Director: National Sanitation Programme of the Department of Human Settlements briefed the Committee on the strategic objective, the background, definition and the focus areas of the National Sanitation Programme. The briefing included an organogram of the Department as well as the current and ideal regional structure envisaged. The funding challenges were outlined and details of the funds transferred from the Department of Water and Environmental Affairs to thel Department of Human Settlements were provided. The National Sanitation Programme was substantially under-funded under the current Medium Term Expenditure Framework. The Department required a subsidised vehicle system as well. The Head of Administration Systems of the Department of Human Settlements briefed the Committee on the administration systems and the processes that were put in place to control the problem of “double subsidisation”. The briefing included the background to and the objectives of the administration systems, information on the National Housing Needs Register and the progress made in the various phases of implementation by each of the nine provinces. Members of the Committee conceded that the sanitation programme was recently introduced and that the Department should be given an opportunity to deliver results. Members were concerned over the potential for fraud and corruption in the administration systems developed by the Department. Members commented on the poor quality of and inadequacy of the toilets provided in many rural and urban areas. Members queried the need for Departmental officials to operate from hotels rather than provincial or local government offices.', 'https://pmg.org.za/committee-meeting/11806/', 0),
    (11827, 'Human Settlements, Water and Sanitation', 91, '2010-08-11', 'Sectional Title Schemes Management Bill & Community Schemes Ombud Service Bill: Departmental briefing', 'The National Department of Human Settlements (the Department) briefed the Committee on the Sectional Titles Schemes Management Bill [B20-2010].The aim of this Bill was to give effect to Cabinet’s Strategy to bring all housing-related legislation presently administered by other departments under the roof of the Department of Human Settlements. The background was outlined, and it was noted that the Bill would essentially take over all sections from the Sectional Titles Act, which was administered by the Minister of Rural Development and Land Reform, that dealt with sectional title scheme management, and thus create a new Act that would be administered by the Minister of Human Settlements. The Sectional Titles Act would then only retain the clauses that dealt with surveys and registration of sectional title plans. The two departments had cooperated in the drafting process and continued to do so. The Department noted that the two Bills had been published in 2009 and both departments participated in the public comment process. It was pointed out that complaints or problems relating to sectional title scheme governance could in any event not be dealt with by the Department of Rural Development and Land Reform. The new Bill would also make information about sectional titles schemes more accessible. The Department outlined the clauses of the Bill. Members noted that effectively the existing legislative provisions were being moved from the Sectional Titles Act to the new Bill, wondered if there should not be further fine-tuning of the provisions, asked who contributed comments and what had been the nature of the public contributions. Members noted that they were not prepared to rubber-stamp decisions taken by the previous Parliament, and would need to have the opportunity to study the Bill and the comments before reaching any decisions or proposing any changes. The Department then gave a presentation on the Community Schemes Ombud Service Bill, which was linked to the Sectio', 'https://pmg.org.za/committee-meeting/11827/', 0),
    (11858, 'Human Settlements, Water and Sanitation', 91, '2010-08-17', 'Department on progress made by Special Investigations Unit on fraud and corruption; Voucher Scheme programme: briefing ', 'The Chief Director of Internal Audit, Risk Management and Special Investigations at the National presented on the background of the Special Investigations Unit (SIU)''s performance reports of 2006-2008 as well as the SIU''s action plan. A comprehensive approach to investigations ensued, followed by progress that had been made thus far on investigations as well as the proposed way forward and project highlights. According to the Director General of the National Department of Human Settlements (NDHS), the NDHS had especially budgeted for the SIU to perform its investigations this year. The SIU was not performing the investigations free of charge. There was the concern about criminals repaying the Department over a lengthy 60 month pay-back period. The concern was noted by the Department. The Director of human settlement policy development of the National Department of Human Settlements, briefed the Committee on the Individual Rural Housing Subsidy Voucher Programme. The Rural Housing Loan Fund (RHLF) would negotiate funding reservation with MECs over the Medium Term Expenditure Framework (MTEF) periods. The RHLF had indicated that it would act as the Financial and Administrative Agent and it would evaluate and appoint subsidy administrators. It was initially noted that due to the financial implications and inherent risks attached to the programme, there had been a suggestion to defer the implementation of the programme until the investigations on the establishment of the Housing Development Financed Institution had been concluded. However, the Committee said that the programme should not be deferred as the challenges and financial risks were all too common in national government and could not be seen as a reason to defer the programme. The voucher programme would proceed with its pilot phase.', 'https://pmg.org.za/committee-meeting/11858/', 0),
    (11902, 'Human Settlements, Water and Sanitation', 91, '2010-08-24', 'Co-operative Housing Policy: Department of Human Settlements briefing ', 'The Department of Human Settlements briefed the Committee on Co-operative Housing, which was one of the options provided under the Department''s Social Housing Programme. The State of the Nation Address had identified the need for financial and institutional support for co-operatives and micro-enterprises. A Housing Co-operative was defined as a legal entity whose members worked co-operatively towards their goal of acquiring more affordable housing, shared the ownership, were allocated specific units and shared ownership and responsibility in that housing’s management. The specific terms, including what happened to the share of members who might wish to withdraw, would be specified in the agreement. Typical clauses in a co-operative agreement were outlined. A major advantage was the possibility that individuals could pool their individual State assistance subsidies, thereby saving costs. Further funding was available from the National Housing Subsidy Programme, the National Housing Finance Corporation and international donors, who had made a considerable contribution to this sector thus far. A co-operative provided the legal structure for the establishment of economic activities which would increase the sustainability of the co-operative and contribute to the livelihood of members. It also engendered a spirit of Ubuntu. Support structures were available for co-operatives such as the Co-operatives Act, the Social Housing Foundation, the South African Housing Co-operative Association and Technical Advisory Services. Possible disadvantages were linked to people still not being receptive to the idea of co-ownership, focusing on individual ownership and being suspicious of other options. The viability of the co-operative could be compromised if members defaulted on their monthly payments and did not fulfill their other obligations towards the upkeep of the co-operative. At present co-operatives could only be located in the Restructuring Zones identified by municipalities.', 'https://pmg.org.za/committee-meeting/11902/', 0),
    (11970, 'Human Settlements, Water and Sanitation', 91, '2010-08-31', 'Department of Human Settlements on 1st Quarter 2010 Performance', 'The Department of Human Settlements presented the Committee with the first quarter national expenditure of its R16, 2 billion budget for 2010/11. The Department allocated only 6.42% on national expenditure and 93.58% of its budget to provincial conditional grants thus emphasising that the provinces were the implementing agencies. The Department provided the figures for expenditure in its five national programmes and reported that it had spent 22% of its allocated budget for the 1 st quarter. Members commended the Department on the implementation of budget allocations according to provincial business plans. However, they queried the role of the Department in implementing development in the provinces and monitoring their progress. The Department emphasised that they were not the implementing agency. The lack of staffing for departmental agencies despite money being allocated to those agencies, was queried. Comment was passed on the slow pace of restructuring in the Department and the need to ensure delivery happened at a faster pace. The Thubelisha Homes expenditure was queried as this agency was supposed to have stopped operating. Members equated lack of expenditure in provinces with the failure to provide service delivery. The National Department for Human Settlements said that they had requested that provincial allocations be kept at National Treasury as opposed to Provincial Treasuries. This was because Provincial Treasuries tended to allocate money earmarked for Human Settlements to other provincial projects. This hindered delivery and expenditure on specified Human Settlements projects. Quarterly allocations that were unspent by a province were rolled over to the next quarter. The Department was requested to provide the Committee with lists of projects and the level of progress on each one at its next quarterly report.', 'https://pmg.org.za/committee-meeting/11970/', 0),
    (11997, 'Human Settlements, Water and Sanitation', 91, '2010-09-07', 'Sectional Titles Scheme Management Bill [B20-2010]; Community Scheme Ombud Services Bill [B21-2010]: public hearings with Deputy Minister', 'The Committee received three written public submissions on the Sectional Titles Scheme Management Bill and one on the Community Scheme Ombud Services Bill. Only one of these was presented in person. This was a sectional title owner who voiced concerns about dysfunctional bodies corporate. Her apartment complex that needed maintenance but no one was prepared to pay a special levy to have these repairs done. She suggested that bodies corporate maintain cash reserves in proportion to their sizes to cover annual maintenance costs. Ordinary people also needed an avenue to take action against negligent bodies corporate without having to resort to expensive legal proceedings. Members took these suggestions to heart although the establishment of an ombudsman in this legislation would allow for a low-cost avenue for owners. The Committee believed that the other matters raised in the submission were already incorporated into the Bills. The Research Unit presented a research document after consultation with experts on the Bills. Their concerns were explained to the Committee. The state of Queensland in Australia had applicable legislation had been used as a model for the Bills. That legislation however had a chapter dealing with dispute resolution and an appeals process. It was suggested that the two pieces of legislation be merged. Members agreed that they were not ready to do a clause-by-clause review of the Bills. More information was needed. The Committee agreed to adjourn for a week to enable the Department of Human Settlements to incorporate all amendments and suggestions.', 'https://pmg.org.za/committee-meeting/11997/', 0),
    (12050, 'Human Settlements, Water and Sanitation', 91, '2010-09-14', 'Sectional Titles Scheme Management Bill [B20-2010]: deliberations', 'Members questioned the tabling of the Sectional Titles Schemes Management Bill and the Community Schemes Ombud Service Bill as separate Bills. They felt that merging the two pieces of legislation would simplify structures and save on costs. The Department of Human Settlements convinced the Committee that there were sound reasons for separate Bills. Sectional title developments were home to many citizens and easy-to-understand legislation was needed. Deliberations began on the Sectional Titles Schemes Management Bill with an in-depth discussion of each definition in Clause 1. Several issues were raised in discussing the definitions. Members discussed the unsoundness of an owner''s mind, unanimous resolutions and the marital status of owners at some length. The Department was instructed to revisit several matters.', 'https://pmg.org.za/committee-meeting/12050/', 0),
    (12054, 'Human Settlements, Water and Sanitation', 91, '2010-09-16', 'Sectional Titles Scheme Management Bill [B20 – 2010]: deliberations continued', 'The Committee continued with deliberations on the Sectional Titles Scheme Management Bill. The Director: Framework Legislation of the Department of Human Settlements presented Clause 3 of the Bill, which dealt with the functions of the body corporate. Members suggested that a percentage of the contributions paid by owners should be ring-fenced for the maintenance of buildings. The percentage of contributions reserved for maintenance purposes could be specified in the Regulations. The Members could not agree on the issue and postponed further discussion and requested the drafters of the Bill to consider appropriate provisions. Members discussed the training of trustees and whether the cost of the training should be borne by the reserve fund. The Department pointed out that the Community Schemes Ombud Service Bill made provision for the training of trustees by the Ombudsman. The Committee suggested that provision for training was included in the Bill. Members suggested amendments to the wording of the clauses and that certain definitions were included in the Bill. In the afternoon session, the Committee deliberated on Clauses 4 to 12 of the Sectional Titles Scheme Management Bill. They discussed at length the borrowing of money by the body corporate. It was suggested that the term “by special resolution” be added in order to make it clear that the body corporate could only borrow money if a situation necessitated action and if the move was approved by a controlling majority of the owners of a property. There was also a long discussion on how best to optimise the level of responsibility granted to the body corporate to ensure that the interests of tenants were looked after. The Committee agreed that Clause 9(6) governing the rules should be clearer. The current rules would exist on a transitional basis until the Minister had brought those rules forward into the new Act, once promulgated.', 'https://pmg.org.za/committee-meeting/12054/', 0),
    (12065, 'Human Settlements, Water and Sanitation', 91, '2010-10-11', 'Auditor-General''s Audit Report in Department of Human Settlements Annual Report 2009/10 ', 'The Committee was briefed by the Office of the Auditor-General on its Audit Report of the Department of Human Settlements for the 2009/10 financial year. The Department had received an unqualified financial report, but concerns regarding Supply Chain Management, procurement and irregular expenditure persisted. A major issue was the lack of adequate and compliant performance information management systems. Internal control mechanism were found to be wanting. If the Department addressed these, they would be in the clear. Members asked how they could address service delivery problems with the information presented to them and were referred to the provincial Housing Departments annual reports. They asked how the Department was faring and were told by the Office of the Auditor-General that if the Department could put into place the necessary key controls, they could sort out the outstanding issues that had been raised.', 'https://pmg.org.za/committee-meeting/12065/', 0),
    (12100, 'Human Settlements, Water and Sanitation', 91, '2010-10-12', 'Sectional Titles Schemes Management Bill: Continuation of deliberations', 'The Committee continued with deliberations on the clauses of the Sectional Titles Schemes Management Bill [B20-2010], from Clause 13 to Clause 20, noting that the deliberations on the Schedule would stand over until Members had a redrafted version in front of them. In respect of Clause 13, the drafters explained the distinction between an owner of an individual unit in a sectional title building, and the co-owners of the entire building, and explained the reasons why individuals could also elect to take out their own insurance cover over and above the Body Corporate cover. However, in this Clause and elsewhere, Members commented that the wording was not clear and asked that attention be paid to clarifying it, using plainer language. Although a Member suggested that it might be possible to simply delete some subclauses, other Members cautioned that this could have an effect on cross-referencing in other legislation, and urged caution in this. A Member suggested that a reference might need to be corrected, in Clause 14(b). In respect of Clause 15, Members suggested that consideration be given to the substitution of “local authority” with “municipality”. The drafters explained the legal role of the administrator. In respect of Clause 16, the drafters explained why a building may be regarded as effectively destroyed if it was impossible to repair, and Members asked the drafters to try to redraft Clauses 16(1)(a) to (c) to make the meaning clearer. Members also asked that a definition be included for “Advisory Council”. For Clause 17, the drafters clarified the composition of the Advisory Council, but Members asked that a quorum requirement be inserted, rather than providing for alternates, and that the words “all inclusive” should be used in Clause 17(5). They also suggested that the Bill state that members of the Advisory Council should elect an acting Chairperson themselves if the Ombudsman was not available, and that the references to the Minister “instructing” or “d', 'https://pmg.org.za/committee-meeting/12100/', 0),
    (12110, 'Human Settlements, Water and Sanitation', 91, '2010-10-13', 'Annual Reports for the 2009/10 Financial Year of the Housing Development Agency, National Housing Finance Corporation, National Urban Reconstruction and Housing Agency & Department of Human Settlements ', 'The Committee was briefed by the Housing Development Agency, the National Housing Finance Corporation, the National Urban Reconstruction and Housing Agency and the Department of Human Settlements on their annual reports for the 2009/10 financial year. The Financial and Fiscal Commission commented on the annual report of the Department. The Chief Executive Officer of the Housing Development Agency presented the annual report of the Agency to the Committee. The HDA had found that coordinated planning and monitoring was difficult because of the number of Government departments involved in the provision of housing. Progress was made in compiling an inventory of State-owned land. The Board of the HDA was meeting on a regular basis and the sub-committees were functional. The required policies and procedures had been finalised but the regulations and mandate were still under discussion. The Agency had received a clean audit report on statutory compliance but a qualification was issued because the lease agreements for photocopiers were for a five-year rather than a three-year term. Financial and Programme Reporting Compliance was achieved and 83% of staff posts were filled. The total expenditure for the period amounted to R43 million and a net surplus of R19 million was declared. Members asked questions about the progress made on the N2 Gateway Housing Project, the problems experienced with the Joe Slovo Flats project, the attendance record of Board members, the transfer of suitable State-owned land for housing purposes, the delays experienced with the acquisition of the Servcon properties, the identification of beneficiaries for the Konubia project, the need to purchase privately-owned land and the status of the agreements signed with the provincial authorities. The Chief Executive Officer and Chief Financial Officer of the National Housing Finance Corporation presented the annual report for 2009/10 to the Committee. The Corporation was adversely affected by the difficult ', 'https://pmg.org.za/committee-meeting/12110/', 0),
    (12111, 'Human Settlements, Water and Sanitation', 91, '2010-10-14', 'Consideration of the Annual Reports for  2009/10 of the National Home Builders Registration Council, Rural Housing Loan Fund ; Response by the Department of Human Settlements on Human Rights Commission Report', 'The Committee was briefed by the Chief Executive Officer and the Chief Financial Officer of the National Home Builders Registration Council on the 2009/10 annual report. The economic recession had severely impacted on the Council and resulted in a decline in the number of housing units registered and projects enrolled. Income derived from enrolment fees had remained static but expenditure had increased, despite the implementation of cost-savings. A net surplus of R215.6 million was declared but the Council warned that the entity would not continue to be financially viable if the current economic conditions prevailed. Members requested explanations of all the items reported as fruitless and wasteful expenditure reported by the Auditor-General. Questions were asked about the late payments received from Government, the late enrolment of projects, the decline in the number of housing units registered, the transfer of R105 million from the warranty fund, the equity investments made without the permission of the minister and the National Treasury, the payment of bonuses despite the financial pressure on the Council, the appointment of inspectors, the action taken against contractors that delivered shoddy workmanship, the measures implemented to prevent corruption involving inspectors and the disciplinary action taken against employees responsible for the wasteful expenditure. The Chief Executive Officer of the Rural Housing Loan Fund presented the Fund ’ s 1009/10 annual report to the Committee. The Fund had received unqualified audit reports since its inception. The fund had achieved most of the impact targets set for the year, although the number of loans granted had decreased as a result of the economic recession. The Fund had declared a surplus of R28.9 million. Members asked questions about the profit made in the disposal of the Bayport investment, the attendance record of the Chairperson of the Board, the remuneration of directors, the interest rate charged by the F', 'https://pmg.org.za/committee-meeting/12111/', 0),
    (12149, 'Human Settlements, Water and Sanitation', 91, '2010-10-18', 'Sectional Titles Schemes Management Bill [B 20-2010]: Deliberations', 'The Committee discussed the proposed amendments to the Sectional Titles Schemes Management Bill. In clause 1 the definitions of “special resolution” and “unanimous resolution” were completely changed so as to simplify and clarify their meanings. The definition of “local authority” was omitted and substituted by “local municipality”. This was done in order to avoid confusion as to which type of local authority was referred to, since there were many different types of local government. In clause 3, a new subsection (b) was inserted. This provision compelled bodies corporate to maintain a reserve fund in such amounts as are reasonably sufficient to cover the cost of future maintenance and repair of common property but not less than such amounts as may be prescribed by the Minister. Clause 6 was a new insertion, which specified how bodies corporate should hold their meetings. In clause 13, subsection (2) was omitted and substituted by a new provision which reads as follows: “where damage to a section is covered by valid insurance policies taken out by the body corporate and the owner, the body corporate’s insurer must make good the damage and only if it fails to do so is the owner’s insurer liable to do so”. This provision provoked a lot of discussion with Members arguing that an owner should be allowed to claim from a second insurance company if they had premiums. It was agreed that further legal advice and further discussions were needed on this matter. It was noted that the Bill would only be adopted after the Community Schemes Ombud Services Bill had been considered.', 'https://pmg.org.za/committee-meeting/12149/', 0),
    (12179, 'Human Settlements, Water and Sanitation', 91, '2010-10-19', 'Department of Human Settlements: Deliberation on Budget Review and Recommendation Report (BRRR) 2010', 'The Senior Researcher read the Draft Budget Review and Recommendation Report page by page while the Committee made corrections to grammar and sentence construction at the same time. The Committee emphasised that there should be a clear distinction between the mandate of the Committee and that of Parliament. The Chairperson informed the Committee that the report was still work in progress as some reports and information was still awaited. Consideration of the Report was postponed pending arrival of these reports and information.', 'https://pmg.org.za/committee-meeting/12179/', 0),
    (12185, 'Human Settlements, Water and Sanitation', 91, '2010-10-20', 'Human Settlements: Budgetary Review and Recommendation Report 2010', 'The Senior Researcher, Ms Berenice Paulse, read the Draft Budget Review and Recommendation Report) page by page and the Committee did grammatical corrections and sentence construction. The amended draft report still had incomplete sentences and information missing as the Report compiling team was still waiting for the Department of Human Settlements to furnish it with the relevant information. The Chairperson informed the Committee that the Department had promised to give the team the information in the afternoon of that day. Members reminded the team that the report was for the public so they were to use full names and put abbreviations inside brackets. Some of the information that was still outstanding from the report included: analysis of the Department’s Prevailing Strategic and Operational Plan, performance summary of the National Home Builders Registration Council, and a report of the Standing Committee on Public Accounts. The Committee congratulated and praised the team for the excellent job it had done in compiling the Report. The dedication and job done by the team in compiling the Report was highly praised by the Committee. The Report was adopted with amendments after sentence constructions and grammatical corrections.', 'https://pmg.org.za/committee-meeting/12185/', 0),
    (12231, 'Human Settlements, Water and Sanitation', 91, '2010-10-25', 'Community Schemes Ombud Service Bill [B21-2010]: Department of Human Settlements: briefing ', 'The Department of Human Settlements briefed the Committee on the business case for the Schemes Ombud Service Bill [B21-2010]. The increased number of housing community schemes created the need for an Ombud Service. At present there was no effective dispute resolution system in this sector. The Ombud Service would ensure independence, fairness and impartiality in disputes. It would also promote uniformity and consistency and provide a remedy and protection for the parties involved. The Ombud Service would be a public entity with a board. Subordinate to the board would be the office of the Chief Ombud. The service would comply with the Public Finance Management Act. The service would have three regional offices in Gauteng , KwaZulu-Natal and the Western Cape to begin with. These provinces were chosen since they had a large number of community schemes. The other provinces would also receive the service since the ombud would work like a circuit court. Members of the African National Congress agreed that people had to pay for the service unless they were indigent, said that the office should be accessible to the public and not be another bureaucratic nightmare, and asked whether the cost had been worked out and how people in the other six provinces would access the service. A Member of the Democratic Alliance said that these six provinces needed this service and that it was important for the Department to explain how it would work. The cost to the consumer for this service was also of concern. It was important to know how much extra would be applied to levies. Board members must declare their interests. The Committee needed a business plan from the Department with more detail. The manner in which the levy was determined also needed to be explained. There was concern that enforcing the decisions of the ombud would be a problem. A Member of the Congress of the People suggested that the other six provinces could have satellite offices, perhaps situated in the Department of ', 'https://pmg.org.za/committee-meeting/12231/', 0),
    (12241, 'Human Settlements, Water and Sanitation', 91, '2010-10-28', 'Mass Housing Solutions briefing on Wall Ties and Forms Building System ', 'A presentation was given to the Committee on mass sustainable development housing solutions, particularly the possibilities that the Wall Ties and Forms system offered for the South African market. Wall Ties and Forms, an American company, was shortly to open offices in South Africa, and had formed an alliance with Maxwell Moss and Associates, a South African company, and the Tagos Group, Texas, which worked internationally. Maxwell Moss and Associates had realised that the major challenges lay in trying to address the huge housing backlog, of 400 000 units in Cape Town alone, along with finance issues, the need to attract appropriate investment and to locate non-traditional funding into the sector, which had to offer innovation. Contractors would have to be skilled and trained and standards set. Wall Ties and Forms had successfully met these challenges in many developing countries and offered solutions borne out of its experience. Essentially, Wall Ties and Forms used aluminium, rather than mild steel shutters, because they did not corrode, were light and therefore easier for women to set up, locked into a rigid system, and offered the potential for add-ons to add aesthetics, but not extra costs, to the building. A concrete solution would be poured in. Openings were a standard size, allowing for mass-ordering of windows and doors. Slabs, the electrical box, plumbing and wire mesh were supplied ready-made and could simply be inserted. A major advantage was that it could be rolled out much more rapidly than other systems. In addition, job security was provided to unskilled workers who could be trained in very little time to do the building, whilst water saving devices and solar generating systems would be inbuilt. The company supplying the concrete had won the award for greenest cement in South Africa, had introduced a carbon rating system, and was a leading black-controlled materials group. The experiences of Wall Ties and Forms in the past extended to multi-unit ap', 'https://pmg.org.za/committee-meeting/12241/', 0),
    (12295, 'Human Settlements, Water and Sanitation', 91, '2010-11-02', 'Eastern Cape Housing Cooperatives, in particular Amalinda Housing Cooperatives; Fitcher''s Corner Progress Report on land bought by Thubelisha; & progress made on rectification of Ducats in East London, Ndlambe Municipality, Alfred Nzo District Municipalit', 'The Department of Human Settlements briefed the Committee on the Eastern Cape Housing Co-operatives. The Department informed the Members about the project’s background and highlighted the many challenges that the Department was facing especially with reference to the Amalinda Project. Among these challenges was the occupation of some of the houses, allocated to families who had saved enough money, by people who had failed to save the required amount. Other challenges were a lack of funding, capacity, office space and infrastructure, and a mismanagement of funds. Members criticised the Amalinda Project’s lack of progress in its 10 years of existence. The same problems continually recurred and were not solved. Members expressed their disappointment about the lack of training and commitment in the co-operatives, the contradictory figures in the report, and the poor management and planning of the project in general. They enquired why more houses were built in urban areas than in rural places. Members also wanted to know why unemployed families were expected to pay to obtain a house and whether such families did not qualify for fully subsidised houses. Members were also concerned with the lack of aid and guidance given to the families to aid them in saving the required amount. Questions were asked around the Swedish funding that the co-operatives had received and why the funding was terminated. Provincial input centred on the responsibilities of the co-operatives and other role players and explained how things had turned out as they had. Non-savers occupying houses, as well as the problems surrounding leadership of the co-operatives, were identified as the biggest hurdles standing in the way of successful completion of the project. Members emphasised the importance of visiting the area in order to determine exactly what the situation was. The lack of time frames set for progress and completion of the project was a further concern. Questions were asked about the board of ', 'https://pmg.org.za/committee-meeting/12295/', 0),
    (12340, 'Human Settlements, Water and Sanitation', 91, '2010-11-08', 'National Housing Programme: Department''s response to SA Human Rights Commission recommendations; Community Schemes Ombud Service Bill deliberations', 'The Department of Human Settlements (DHS) was asked to report back to the Committee on the recommendations to that Department by the South African Human Rights Commission (SAHRC), following its investigation into the 2008 xenophobic attacks. The first recommendation was that the DHS must formulate a policy on the partial formalisation of infrastructure and tenure rights in at-risk informal settlements. The DHS noted that already in August 2004, a National Housing Programme for Upgrading of Informal Settlements (UISP) had been approved, based on best practices and tried and tested South African projects. This was following a phased development approach, and all nine provinces had identified the most critical settlements and commenced with their upgrade. The various phases were described. Issues around obstructive leadership were to be addressed by municipal ward councillors and the community. The second SAHRC recommendation suggested that the DHS must engage with residents of informal and Reconstruction and Development Programme (RDP) settlements in order to raise awareness of existing policies, and also to obtain information about the challenges faced, to enable development of appropriate policies to manage the ownership, sale and rental of shacks and RDP houses. The DHS responded that this was already happening, that all inhabitants and their needs had been identified and recorded, and they were informed of their rights, choices and obligations, and were also given access to funding. However, the Department was unable to control the informal and illegal selling of houses within the proscribed time frame. The SAHRC’s third recommendation was that management perspective should be adopted on informal settlements and undocumented migration into them. The Department said that this was also being done, with a balanced development approach to ensure that rural development needs were also addressed. Although the Department had created a “housing atlas” to document all info', 'https://pmg.org.za/committee-meeting/12340/', 0),
    (12381, 'Human Settlements, Water and Sanitation', 91, '2010-11-15', 'Community Scheme Ombud Services Bill [B21-2010]:  Further Deliberations', 'The Committee continued with discussions on the Community Scheme Ombud Services Bill [B21-2010] (the Bill). The legal drafters from the Department of Human Settlements and the State Law Advisors presented Clauses 14 to 39. Members discussed whether minimum qualifications should be stipulated in Clause 14, and the drafter would look at this. Clause 15 would also be refined so that it was not in contravention of any labour law issues, and the Committee clarified that in Clause 16, suspensions could not take place without pay, but urged that something should be inserted to try to expedite disciplinary measures, probably in the regulations. Once again, the question of time frames was raised in respect of Clause 17, as members were concerned about the long time for which people tended to hold acting positions. In Clause 18, staff recruitment was discussed, and it was suggested that there might need to be consultation with the Minister, although the drafters thought this would delay and complicate matters, and pointed out that the Ombud was already working under board directives. A Member was very concerned about the power to delegate appointment of staff, in Clause 20, but was assured that the specific delegation of powers would also be fixed by the board, in writing, and that there was unlikely to be a danger of junior employees attending to this function. The drafters would remove some tautologous wording. The concerns raised by the public submissions for Clause 21 were summarised, which questioned the appointment and status of adjudicators, and the appointment processes. Members thought it would be preferable to have fewer full time adjudicators to try to keep the structure lean. Four submissions had been made in respect of Clause 22. The first related to whether the Service would be self-funding, and the second claimed that levies collected by community schemes would be another expense against the property, resulting in prices or corporate body levies being increased', 'https://pmg.org.za/committee-meeting/12381/', 0),
    (12385, 'Human Settlements, Water and Sanitation', 91, '2010-11-16', 'Community Scheme Ombud Services Bill: Further Deliberations ', 'The drafters took the Committee through Clauses 40 to 60 of the Community Scheme Ombud Services Bill (the Bill). In Clause 41, it was suggested that the 60 day time limit could be extended if warranted. It was clarified that Clause 42 was intended to allow the Service to reject applications not within its jurisdiction but to make recommendations for referral elsewhere. It was agreed that Clause 44 would also be amended and that both would make it clear that applications may be rejected if applicants did not respond. The drafters explained that the intention of the Bill was to make all proceedings as user-friendly as possible, which was why legal representation would not generally be allowed, but that Clause 43 would be amended by referring also to Clause 52, to clarify the instances in which it could be granted. The public’s concern why the applicant was limited, in Clause 44, to answering matters raised in the submission, was addressed by clarifying that context could be addressed but no new submissions could be raised. The difference between the functions of the ombud and the adjudicators was explained in relation to Clause 47. The Committee requested that reasonable timeframes be suggested by the drafters in relation to Clause 48. Members asked for an assurance that applicants would have been made aware of the costs payable before launching their application, and this was addressed in Clause 49 and would be spelt out in regulations, and also clarified what the costs awards in Clause 53 could entail. Members considered the wording of Clause 50 but agreed to retain the reference to “quickly”. The words “and/or” would be substituted for “and” in Clause 51. Members discussed whether it was appropriate for appeals to the high Court to be limited to questions of law, and discussed the public submission that perhaps a second opinion could be sought, or reviews commenced before referring to the High Court. It had been recommended that further sections be added to empower', 'https://pmg.org.za/committee-meeting/12385/', 0),
    (12419, 'Human Settlements, Water and Sanitation', 91, '2010-11-23', 'Human Settlements delivery issues: Ministerial briefing, Social Housing Regulatory Authority progress report, Committee Report adoption', 'The Minister of Human Settlements delivered a medium term report on the performance of the Department of Human Settlements (DHS) and gave a broad overview of service delivery issues nationally. The Minister indicated that some provinces had not achieved their 50% benchmark for spending of their capital budgets, as reported by the Minister of Finance on 18 November 2010. Only Limpopo and Northern Cape were above the 50% benchmark, with poor performance in Western Cape, the Free State and KwaZulu Natal. However, it was expected that some provinces would make a significant recovery in the next financial term, and intervention strategies had been arranged during the recent MinMEC meetings, with provinces to be given the necessary support to obviate fiscal dumping at the end of the financial year. The Minister then elaborated on the major challenges confronting the Department, noting that these concerned the provision of bulk infrastructure, project management capacity, the lack of a fully integrated approach to human settlements, the need for additional funding in respect of some provinces, and the problems relating to the rectification of shoddy houses and the unblocking of blocked projects. He highlighted the pressure on the Department resulting from the continuous migration from rural to urban areas, and the existence of 2 700 informal settlements, and emphasised the urgency of creating viable and sustainable human settlements. The Department reiterated the urgency during its briefing on the Social Housing Regulatory Authority (SHRA). It was noted that SHRA had been established to regulate and support the performance of the social housing sector, in order to accelerate the delivery of sustainable and financially viable social housing projects. It was noted that the Council for SHRA had been constituted, that a Chief Executive Officer had been appointed, and that appointment of other staff, and the setting up of the necessary processes, were on track. The Council was ', 'https://pmg.org.za/committee-meeting/12419/', 0),
    (12430, 'Human Settlements, Water and Sanitation', 91, '2011-01-16', 'Study Tour Report to Australia', 'The Parliamentary Research Unit briefed the Committee on the Queensland Study Tour Report. The Report contained detail of the delegation’s activities and findings. The purpose of the visit was to learn about the housing policies and practices, and how South Africa could adapt the lessons learned to this country. Members expressed concern about the manner in which young people and the elderly were accommodated in the housing market. It was agreed that the report would be adopted at a later meeting.', 'https://pmg.org.za/committee-meeting/12430/', 0),
    (12442, 'Human Settlements, Water and Sanitation', 91, '2011-01-18', 'Sectional Titles Schemes Management Bill and the Community Schemes Ombud Service Bill: deliberations', 'Members met with representatives of the Office of the Chief State Law Adviser for deliberations around the Sectional Titles Schemes Management Bill and the Community Schemes Ombud Services Bill. A representative of the State Law Adviser’s Office listed the recommendations proposed by the delegation that undertook a study tour to Queensland , Australia . One such recommendation included the suggestion that the issue of tenant participation in Annual General Meetings should be reviewed by the Department and provided for in regulations under the Sectional Titles Schemes Management Bill. The recommendations and report were accepted and adopted. Following this another representative from the State Law Adviser’s Office listed proposed amendments to the Sectional Titles Schemes Management Bill, including the proposal that in Clause 15, on page 9, in line 27, the words “additional term of five years” be omitted and replaced with “or more additional terms of five years, subject to the approval of the Minister”. A member asked whether this proposal was made by the Committee as it appeared to contradict what the Committee had decided previously on this matter. It was agreed that the meeting should be adjourned as the documents handed to members were found to be incomplete.', 'https://pmg.org.za/committee-meeting/12442/', 0),
    (12452, 'Human Settlements, Water and Sanitation', 91, '2011-01-24', 'Sectional Titles Schemes Management Bill; Community Schemes Ombud Service Bill: proposed amendments', 'The Committee met with the State Law Advisers for deliberations on the Sectional Titles Schemes Management Bill and the Community Schemes Ombud Service Bill. One of the representatives said that, with the Community Schemes Ombud Service Bill there was a proposed amendment that under Clause 39 on page 15, after line 16, the following paragraph be inserted: “ (e) an order for the payment or re-payment of a contribution or any other amount.” There was also a proposed amendment under Clause 48, on page 18, form line 2, to omit subsection (1) and to substitute it with the following subsection: “(1) If the ombud does not facilitate a negotiated settlement in terms of section 47, or if such ombud is of the view that a negotiated settlement is unlikely to succeed, the ombud must refer the application together with any submissions and responses thereto to an adjudicator.” Members asked whether any provision was made for certificates of referral being provided, whether the levy amount have to be paid in advance annually, why, in relation to the appeal process, there was both a right to apply to the High Court as well as 30 days to appeal the order, what the Department’s views were on the submission made around making it mandatory for defaulting owners to pay their levies and where, in relation to dissolution, mention was made of the levies to be divided among the members of the body corporate. Following this another representative said that there had been a proposed amendment in the Sectional Titles Schemes Management Bill that a new Clause (Clause 6, dealing with Meeting of bodies corporate) be included. It had also been proposed that Clause 15, which dealt with the Appointment of administrators, be rejected and be substituted with a new Clause. Members asked whether individuals were allowed to hold or three proxies and how long, on average, administrators’ terms lasted for.', 'https://pmg.org.za/committee-meeting/12452/', 0),
    (12480, 'Human Settlements, Water and Sanitation', 91, '2011-01-25', 'PC Human Settlements: Reports on oversight visits to Gauteng Province and Oakdale Sectional Title Block ', 'The Committee met to consider the draft report on its oversight visit to the Oakdale Sectional Title Block and its draft report on its oversight visit to the Gauteng Province . The visit to Oakdale was prompted by a submission by one the sectional title scheme’s owners during the public hearings around the Sectional Titles Schemes Management Bill and the Community Schemes Ombud Service Bill. The Committee had made the following observations as a result of this visit: •due to a lack of proper communication between owners and the body corporate •the on-site inspection of the property (including the yard and its surroundings) had revealed no visible signs of either a lack of or poor maintenance. •it was important for owners to take responsibility when buying into Sectional Title Schemes and to familiarise themselves with the financial statements and trustees’ annual report for the previous year, •those who were renting should be compelled to ensure that the complex was well-maintained at all times •people living in the complex needed to take ownership of their investment, •the complainant was advised to contact the National Association of Sectional Title Owners •the need for two separate budgets (one for day-to-day operations and one for maintenance) was emphasised •it was not the responsibility of the owner that sold his/her unit to pay the special levy but rather that of the new owner. Members called for education to be prioritised in this regard and for legislation to be written in a way which made it more accessible to a wider range of people. A member asked whether anyone other than Ms De Klerk had been spoken to and whether she was satisfied with the outcome of the visit. The Report was adopted. The Committee then went on to discuss its Draft Report on its oversight visit to the Gauteng Province . Members raised concerns around figures on informal settlements which did not seem to correlate and the fact that there were no toilets in Baghdad appeared to go against', 'https://pmg.org.za/committee-meeting/12480/', 0),
    (12485, 'Human Settlements, Water and Sanitation', 91, '2011-01-26', 'Sectional Titles Schemes Management Bill & Community Schemes Ombud Services Bill: Adoption', 'The Committee met with Parliamentary Legal Services Office staff to discuss the proposed amendments to the Sectional Titles Schemes Management Bill. Members raised the point that the ombud needed to be viewed as the first option for people seeking legal remedy, and that the courts should be the last resort. They suggested that electronic media and faxing should be regarded as acceptable methods of delivery of notices to members of the body corporate. They also wanted to limit the number of proxies that an individual could hold. The Committee then debated the Community Schemes Ombud Services Bill, with the Office of the Chief State Law Advisor giving input. Members approved new definitions regarding the “community scheme”. Members expressed concern about the omission of housing cooperatives from the “community scheme” and it was agreed that the relevant definition be redrafted accordingly. Members discussed why Clause 4 (b) had not clearly recognised the role played by conciliators and argued that conciliators played a significant role in dispute resolution and had to be identified alongside adjudicators. Some discussion was held on whether the terms “mediation”and “conciliation” were synonymous and it was agreed that if they were, there was still no harm done in referring to both. It was agreed that Clause 4(b) should be amended to contain wording relating to training for conciliators, adjudicators and other employees of the Service. Members also noted the need to cater for criminal liability for breaches of Clause 11, and this was done by amending Clause 34 with the addition of a new subclause (h). Members agreed upon a new title for Clause 47, and made the necessary consequential changes to the referencing. Members also debated whether to include a clause that provided that the Service must be self-funded after the first three years and noted that there was a provision that the legislation must be reconsidered after that time. It was noted that government assistan', 'https://pmg.org.za/committee-meeting/12485/', 0),
    (12518, 'Human Settlements, Water and Sanitation', 91, '2011-02-08', 'Department on the Quartely Expenditure Report: July-September & October- December 2010', 'The Department of Human Settlements briefed Members on its quarterly expenditure reports for July to September and October to December 2010. The Department outlined its expenditure and also the breakdown of how the allocated budget was spent. The Department also presented and discussed the individual rural housing subsidy voucher programme, which was developed as an alternative subsidy option in rural areas, where project-based housing delivery was not planned for the foreseeable future. A problem that the Department encountered with its budget was a shortfall in spending, resulting in a possible roll-over amount that would be shown by the end of the financial year. The Department showed figures indicating the service delivery levels for the second and third quarters of the financial year by indicating how many houses were being built per province. Among the areas of expenditure outlined and presented in detail were administration, housing planning and delivery support as well as strategic relations and governance. One of the key issues raised in the presentation was the low percentage of spending reported in most provinces. The Department admitted that this was a major concern for it as it negatively impacted serviced delivery across the country. They agreed that a drastic measure of action was needed to address this issue. This was concerning to both members and the Department as there was still such a huge gap in providing infrastructure to communities. The reasons the Department gave for this deficit in spending was because many vacancies in the Department was not being filled, resulting in a lack of capacity to fill certain responsibilities in the Department. Also, at provincial level, some provinces were not using the allocated budget resulting in the Department having to relocate that money to other provinces that needed it more. Member asked questions relating to why this under-spending was occurring. They wanted to know how the Department had planned to fil', 'https://pmg.org.za/committee-meeting/12518/', 0),
    (12555, 'Human Settlements, Water and Sanitation', 91, '2011-02-15', 'Rural Infrastructure Programme & Innovative Housing Technologies: Department of Human Settlements briefing', 'The Department of Human Settlements briefed Members on innovative housing technologies. These had not been well-accepted by beneficiaries. People felt that these structures were inferior to other Government-provided structures. Beneficiaries tended to believe that they were devalued by the state and were given an inferior product. There were also problems with structural damages due to excessive rainfall. The Department admitted that a major challenge with using alternative technologies was that they exceeded the cost of the normal housing subsidy available. Also, because most of the materials were made and standardisation was decided overseas, the Department saw a problem with maintenance in the future. In addition to this, building inspection was lacking as the country’s current inspectors were not equipped to do thorough inspections due to a lack of training. Members said that in order for alternative building to be accepted in communities as a non-inferior product, more access should be given to middle class communities. They were concerned about the lack of certification as this was crucial to ensure quality processes. They also thought that this project would not contribute sufficiently to local job creation as overseas companies were being used. The Department then presented the progress made with regards to the Rural Household Infrastructure Programme. The Department was tasked with the issue of sanitation. It outlined the progress made in each province where implementation took place. It highlighted some of the challenges faced in those provinces as many municipalities were unhappy with the service provider, namely the Independent Development Trust. Municipalities were unhappy because these providers were using contracted labour, whereas they were convinced that local labourers were to be used to install toilets. Due to unforeseen circumstances such as rain hampering progress, it was expected that only 75% of the target amount of toilets would be installed ', 'https://pmg.org.za/committee-meeting/12555/', 0),
    (12599, 'Human Settlements, Water and Sanitation', 91, '2011-02-22', 'National Planning Commission on urban development and movement trends; Department of Human Settlements on progress of the Scottsdene / Kraaifontein Self Help Project & North West Housing Corporation ', 'The National Planning Commission discussed issues of urban development and movement trends. The pattern of movement from rural to urban areas had been slow and the Commission wanted to increase the percentage of people in the cities in order to increase employment opportunities for disadvantaged people. They found that the urbanisation trends were still under par because of the legacy of apartheid which restricted urban living for the poor. Infrastructure needed to be upgraded to accommodate the movement of people to the bigger cities. The percentage of people having to travel great distances to get to work and other places of service was estimated to be 65%. This was unfavourable as it meant these people were spending an average of 8% of their salaries on transportation costs alone. It was a discouraging factor to those people trying to find employment and sustain their families. The National Planning Commission was working on plans to improve infrastructure in and around cities to accommodate more people living in the epicentre of cities. It had the mandate to inform the Department on suitable land available for development of new and innovative housing initiatives. Members suggested that the Commission look to new ideas which were outside of the box. They thought that the idea of developing new cities would be feasible in the future. Members said that these types of concerns had been raised before and thought that it was time to do something about these types of issues. Prime land allocated for development was another concern as the cost of this land was higher than usual leading to higher rates and tax amounts which most people could not afford. The Department of Human Settlements gave a presentation on the progress of the Scottsdene / Kraaifontein Self help project. This project was initiated in 1988 and there were issues with the implementation of the third phase of the project. Some beneficiaries had not received there plots and building materials as promised', 'https://pmg.org.za/committee-meeting/12599/', 0),
    (12686, 'Human Settlements, Water and Sanitation', 91, '2011-03-08', 'Department of Human Settlements & Housing Development Agency (HDA) on strategic and performance plans: briefing', 'The Committee met with the Department of Human Settlements and the Housing Development Agency to discuss the Medium Term Strategic and Performance plans. These were in line with the Outcome 8 Agreement approach adopted by the Department which focused on improving service delivery within the human settlements domain. Water and sanitation remained a contentious issue and focus was high on improving the quality of home life for citizens. The Department outlined its budget allocation and the breakdown per programme as well as the allocation per province. The Department admitted that there were some challenges in fulfilling its mandate but this would be addressed by the establishment of the National Programme Management Unit which would support provincial and municipal programme management. Members were concerned about the lack of communication between national and provincial departments. They wanted business plans to be aligned with realistic targets and outcomes. An issue of unaccredited municipalities also came to the fore whereby some municipalities received an allocation from the urban settlement development grant without having the necessary accreditation as a Metropole. They asked whether these municipalities were confirmed to be accredited or not as some newspaper reports conflicted with what the Department had presented. The Housing Development Agency followed with its presentation. The Agency had been tasked with the acquisition of well-located publicly owned land and buildings for the development of housing. Thus far, the Agency had done well by acquiring 33 000 hectares of suitable land for development. The N2 Gateway and Zanemvula projects were up to date and going forth well. The Agency had a central role in the recently agreed Outcome 8 Development Agreement and the public land transfer process defined within it. The Agency was also involved in taking up existing projects which were not moving forward or which had been cancelled. Members were satisfied ove', 'https://pmg.org.za/committee-meeting/12686/', 0),
    (12733, 'Human Settlements, Water and Sanitation', 91, '2011-03-15', 'National Home Builders Registration Council (NHBRC), Rural Home Loan Fund (RHLF) and Social Housing Regulatory Authority (SHRA): strategic planning briefings', 'The Business plan of the Social Housing Regulatory Authority was presented, with reference to strategic objectives, key activities, organisational structure, budget, risk, and logos. The Committee members asked about the funding amount differences between the presentation and what the committee had received; what the Social Housing Regulatory Authority plan for this delivery of the 80 000 housing units proposed in the State of the Nation address was, how many institutions were accredited and in which provinces and how these institutions were accredited without a register, and if the Social Housing Regulatory Authority had a plan to address the risks identified by the Department. The Social Housing Regulatory Authority responded that the funding of R226 million was capital and R24 million was operational (slide 21). The 80 000 units announced by the President had been broken down into the social housing, private sector, institutional and rental housing. The Social Housing Regulatory Authority would concentrate on rental and social housing. A full report of the accreditation of the institutions would be given by the end of the month. The Social Housing Regulatory Authority planned to have a risk workshop in June to make sure it had identified and mitigated risks. The Social Housing Regulatory Authority also planned to appoint internal auditors to mitigate these risks. The Rural Housing Loan Fund presented its Strategic Plan for 2011/12. The outline of the Fund’s contribution to Outcome 8 was presented. This was to encourage intermediaries to explore financing opportunities in informal household upgrading and backyard rentals. The funding grants from the departments for 2011/12 and the projected increase in budget for 2012/13 were presented. The Committee members praised the Fund for its presentation, and raised questions regarding the large increase in staff wage provision, the definition of a traditional house, whether there were awareness campaigns for access to the', 'https://pmg.org.za/committee-meeting/12733/', 0),
    (12741, 'Human Settlements, Water and Sanitation', 91, '2011-03-15', 'National Urban Reconstruction Agency & National Housing Finance Corporation 2011 Strategic Plans', 'The Managing Director and Chief Financial Officer of the National Urban Reconstruction Agency presented the organisation’s strategic business plan and budget for 2011/12. The Agency had identified the collection of outstanding debts; the re-focus of the subsidised housing programme; increased lending to the affordable housing market; maintaining the volume of loans for infrastructure programmes and augmenting the revenue stream as key objectives. The budgeted income from operations for 2011/12 was R49.8 million and administration expenditure was R48.5 million. Provision was made for project and operational losses and a deficit of R5.5 million was projected. Total equity and liabilities would increase to R599 million. The Agency forecast a surplus of R1.9 million for 2012/13, increasing to R13 million for 2014/15. Members asked questions about the recovery of debt, the projected project losses, the high rejection rate, the nature of fee-based revenue opportunities, the involvement in the upgrading of informal settlements, the training provided by the Agency, the appointment of external consultants to provide services and the opportunities for women and the youth in the housing sector. The Chief Executive Officer and Chief Financial Officer of the National Housing Finance Corporation presented the strategic plan and budget for the period 2012 to 2014 to the Committee. The Corporation had identified the expansion of housing finance activities; facilitating increased lending by financial institutions; mobilising funding for human settlement programmes; ensuring the sustainability of the entity and the stimulation of the low- to middle-income housing sector as key strategic objectives. The Corporation planned to introduce the Mortgage Default Insurance programme in early 2012. The budgeted revenue for 2012 was R282 million, increasing to R612 million for 2013 and R582 million for 2014. The budgeted net profit for 2012 was R48 million, increasing to R90 million for 2013 a', 'https://pmg.org.za/committee-meeting/12741/', 0),
    (12778, 'Human Settlements, Water and Sanitation', 91, '2011-03-22', 'Urban Settlement Development Grant, Rural Household Infrastructure Grant and accreditation for cities: briefing by National Treasury ', 'National Treasury explained the new grants that had been allocated via the Department of Human Settlements: the Urban Settlement Development Grant and the Rural Household Infrastructure Grant as well as the accreditation of municipalities. Despite large amounts spent over the last sixteen years on housing, the country was nowhere near resolving its housing crises. Currently the housing backlog was three million units. Current funding and funding models did not address informal settlements. Informal settlements were growing continually. For cities the question was: How does one move away from the spatial settlement patterns created by apartheid, so that the poor could be settled closer to economic hubs and be integrated into the life of the city. The current interventions by government did not address this issue, in fact it entrenched apartheid spatial patterns. The Urban Settlement Development Grant would make it possible for cities to plan in a more integrated way. To not only provide houses, but to provide services like water and sanitation, sports facilities, schools and economic opportunities all near transport corridors that connected to other parts of the city. It would also bring poor people closer to city centres, to make them part of the integrated city, and this would assist with the policy of densification. When people lived closer to the city centres, they had to travel shorter distances to work, which had a positive impact on the environment. They also spent a smaller portion of their income on transport. The Rural Household Infrastructure Grant addressed the burning issue of water supply and sanitation in rural areas. According to the Constitution, housing was a function that rested with the national and provincial governments. However, the Constitution made provision that, where local government was better placed to perform a function, the function could be entrusted to a local authority, but such an authority had to qualify to earn the right. It had ', 'https://pmg.org.za/committee-meeting/12778/', 0),
    (12848, 'Human Settlements, Water and Sanitation', 91, '2011-04-10', 'PC Human Settlements: Consideration of Committee Strategic Planning Report & Annual Programme ', 'The Committee met to consider its strategic planning report as well as its annual programme and budget. The Committee did not have a quorum and could therefore not adopt the two draft documents. It was agreed that the Committee would adopt the two documents in its next meeting.', 'https://pmg.org.za/committee-meeting/12848/', 0),
    (12868, 'Human Settlements, Water and Sanitation', 91, '2011-04-12', 'National & Provincial Departments of Human Settlements 2011/12 business plans', 'The provincial and national Departments of Human Settlements presented their 2011/12 business plans to the Committee, focusing on programmes of informal settlement upgrading, affordable rental housing, affordable housing finance, land acquisition, rural housing and rectification. Informal settlement upgrading and rectification was high on the agenda for most provinces. The North West , Free State and Western Cape planned to spend at least half of their budgets on informal settlement upgrading alone. Limpopo, Kwazulu Natal and Mpumalanga were focusing more on the provision of rural housing, with Gauteng and the Eastern Cape spending a considerable amount towards rectification. The Northern Cape , because of its smaller budget compared to the other provinces, was focusing more on planning programmes. Each province respectively spoke to the Committee about its specific targets which were not included in the first presentation, such as job creation, the acquisition of land in conjunction with the Housing Development Agency (HDA), emergency housing in provinces affected by heavy rains, the ways in which beneficiaries were allocated, and previous non-enrolled projects which had caused major concern. The work being done with other departments and with municipalities was also mentioned. Members wanted to know why allocations to different programmes across provinces differed so much. They asked questions around the specifications of the informal settlement upgrades, as to whether these would be permanent or temporary. Rectification was of major concern to members as money was being spent wastefully to demolish and rebuild homes due to substandard work, especially houses built before 2002. Members questioned the progress on blocked projects, especially those in the Northern Cape which had been part of the North West prior to the re-setting of cross-border municipality boundaries. Members asked whether the amount of R908 million had been repaid to the Department by the municip', 'https://pmg.org.za/committee-meeting/12868/', 0),
    (12888, 'Human Settlements, Water and Sanitation', 91, '2011-04-13', 'Rural Household Infrastructure Programme: briefing by Department of Human Settlements', 'The Department of Human Settlements presented the progress on the Rural Household Infrastructure programme, more specifically its sanitation component. Since 2007, government had identified rural development as one of the country’s major priorities. In accordance with this, the Department had identified areas in 8 provinces of the country to implement sanitation service. They appointed two Service Providers through open tender processes. As at 4 April 2011, 5497 units had been completed form a total of 11920. There were various reasons for the delay in progress, but it was mainly because one Service Provider, namely the Independent Development Trust (IDT), was not using local labourers as promised to community members. This caused some with some communities refusing the implementation of the programme. Delays were also caused by heavy rains and hard rocky conditions which hampered digging progress. In some provinces targets had been met in the respective municipalities and community members were pleased with the services received. Members were disappointed that the progress on sanitation was so slow. They were concerned that service delivery was lacking and requested that the department step in to resolve these issues. They wanted to know what the process of tender for these service providers entailed, and how it was possible for a provider with such little experience to be awarded the tender. Members asked that the Department resolve this issue as soon as possible, and remove the IDT as a Service Provider if needed. Members also felt it was unfair that the inaccessibility of farm areas was used as an excuse as to why these people had not received services up to date.', 'https://pmg.org.za/committee-meeting/12888/', 0),
    (12959, 'Human Settlements, Water and Sanitation', 91, '2011-05-24', 'North-West Housing Corporation Board briefing; Establishment of Project Management Unit and plans to monitor, manage and evaluate projects to eliminate shoddy work: Department of Human Settlements briefing', 'The Portfolio Committee was briefed by a delegation from the North West Province including the Chairperson and the Acting Chief Executive Officer of the North-West Housing Corporation Board on the winding down process of the Corporation. This was a follow up to a previous meeting at which serious concerns had been raised and members of the Board had been requested to appear before the Committee. The Department of Human Settlements informed the Committee that the report had not been submitted to the provincial Exco and requested that the information be treated as confidential due to the sensitivity of its content. This elicited strong reaction and debate by Members that included whether the media should be allowed to be present. The Chairperson ruled that the meeting could not be declared closed as the proper procedure had not been followed. Challenges to the winding down process of the Corporation were the complexity of the issues involved which related largely to its historical background. It was a Schedule (3) Public Entity in terms of the Public Finance Management Act and had been established in terms of the North West Housing Corporation Act of 1982 as amended. It owned rental stock, flats, vacant stands and instalment sale houses not only in the North West Province but in Gauteng, the Northern Cape and Free State Provinces. The Corporation started to experience serious cash flow problems since 2005 when the property development function was transferred to municipalities. Exco later took a decision to transfer all provincial residential properties to the Corporation to let or sell in order for the Corporation to generate its own income. However, the properties transferred to the Corporation were never identified or quantified nor was proper registration done in the name of the Corporation. In addition townships (with the exception of Mafikeng) inherited from the former Bophuthatswana were not registered in the township register and the selling and transferring o', 'https://pmg.org.za/committee-meeting/12959/', 0),
    (12973, 'Human Settlements, Water and Sanitation', 91, '2011-05-26', '4th Quarter provincial performance, Inter-Governmental Relations Protocol between National Department & accredited municipalities, Urban Settlement Development Grant: Department briefing', 'The Department of Human Settlements gave an overview of the Fourth Quarter performance by provinces which included a complete picture of the year’s expenditure by the provinces. Concerns were raised about under spending and why fewer houses were built. The department’s response to the drop in the number of houses built was the increased cost of construction and inflation plus the subsidy had not increased for several years. The department had to deliver more with less. The department was still waiting for the figure for serviced sites completed in the Free State and would come back with a more accurate figure, together with what the steps would be taken about the under-performance. One of the responses to under-performance was the Urban Settlement Development Grant (USDG) which was meant to assist provinces to change their behaviour. The Chairperson did not think government could be proud of the rate of delivery; the pace that Human Settlements was moving at did not give hope. Not sufficient was being delivered in order to reach the President’s expectations, and the challenge was to ensure that the Millennium Development Goals were met in terms of slum clearance. The Committee was concerned about the Free State and requested more information on the R1.3 billion spent on only 5 000 units. The Free State withdrew 17 000 units because there was no money, but at the end of the year there was budgeted money that they could not spend. However, once the Minister announced that he would relocate funds from the Free State to another province that was able to spend, the money disappeared and there was spiking in the expenditure. The Committee needed answers. Where was that building material, where was it kept, kept for whom, and was there security? A report on this was requested. Accreditation The rationale for municipal accreditation was that it would assist coordinated development and horizontal integration. All funding ended up in a local authority, where it was coordinate', 'https://pmg.org.za/committee-meeting/12973/', 0),
    (12998, 'Human Settlements, Water and Sanitation', 91, '2011-05-31', 'Construction Education and Training Authority (CETA) & Outcome 8 service delivery agreements: progress reports ', 'The Committee met to hear briefings from the Department of Human Settlements on the Rural Household Infrastructure Programme Performance Expenditure Report and a report by the Construction Education and Training CETA on their programme and progress made in achieving their objectives of the programmes; Outcome 8 Service Delivery Agreements signed between the department and other respective departments. The Construction Education and Training Authority (CETA) had been under administration since March 2011. Its Administrator presented an analysis of the problems and challenges affecting CETA. Prior to the move of the SETAs to the Department of Higher Education and Training, the CETA had concentrated on short skills programmes and learnerships and not bursaries and apprenticeships. This had been an exercise in futility as these short training stints were not appropriate training and left people with meaningless certification. The CETA would therefore be focusing on a fuller qualification as they move forward. One of the key areas in the construction industry was Adult Based Education and Training (ABET) with most of the construction workers coming to the programme because of illiteracy. However, they had discovered the ABET model was a generic one which was based on how to teach people to read, write and do basic calculation. In order to make it more appropriate and more attractive to their industries, they should change it and make it more construction specific. Also there had been no Recognition of Prior Learning. This had to be activated. There was no tracking of end results. For example, in terms of new venture creation and support in the past five years, they did not have figures for how many of these trainees had gone on to establish venture entities. The focus would be more on training provided by public institutions and government departments rather than private providers. There had been much corruption – as many as 80% of the projects had a corrupt element to t', 'https://pmg.org.za/committee-meeting/12998/', 0),
    (13064, 'Human Settlements, Water and Sanitation', 91, '2011-06-14', 'Human Settlements Beneficiary Occupancy Audit & Sanitation Projects: Departmental briefing; Development Bank of Southern Africa''s assistance in capacity building', 'The Committee met with the Department of Human Settlements (the DHS) and Development Bank of Southern Africa (DBSA) to discuss issues related to human settlements. DBSA reported that it provided assistance to the Department and municipalities in terms of capacity building and assistance with planning or financing, to provide effective human settlements, in line with government outcomes. DBSA gave an overview of the type of assistance, and its strategic approach, including outlining the diversity of DBSA’s loan book was explored, and its exposure to the municipal sector in South Africa . Critical human settlements challenges and blockages were discussed. The content of the Memorandum of Understanding between the DHS and DBSA was explained, and examples of DBSA projects and investment programmes were presented. Members commented that the role of DBSA within provinces and municipalities were crucial for the successful development of human settlements, and questioned whether its support extended to rural municipalities, and what employment opportunities were provided, particularly for women and persons with disabilities. They also interrogated its involvement with the National Planning Commission and its relationship with the Housing Development Agency, particularly because of concerns around duplication of functions in land acquisition. Members commented that a further challenge, which had not been mentioned, included poor workmanship of some housing projects. The Department then presented its findings on illegal occupation, following a beneficiary audit done in the 2009/2010 financial year. The legislative provisions around illegal occupation, and definitions, were presented, as well as a summary of a municipality’s obligations both in terms of the Extension of Security of Tenure Act and the Grootboom Constitutional Court judgment. It was noted that it was the responsibility of local government to compile waiting lists from the lists of those qualifying for houses, an', 'https://pmg.org.za/committee-meeting/13064/', 0),
    (13119, 'Human Settlements, Water and Sanitation', 91, '2011-06-21', 'Sanitation programme: Minister of Human Settlements briefing', 'The Minister of Human Settlements, Hon Tokyo Sexwale, was invited to address the Committee on the recent transfer of the sanitation programme to the Department of Human Settlements, and the problems that the Committee had highlighted in its recent report, related to the sanitation service delivery by the Independent Development Trust (IDT). Whilst the Committee recognised that a new programme took time to implement, it had been particularly concerned at the funds already released, with little result. The Committee pointed out that National Treasury had earlier reported that the IDT, in one financial year, had received R22.6 billion from eighteen different departments, with most of the funds being transferred in a spike right at the end of the financial year. The IDT, in its tender documents, indicated that it had no expertise in sanitation, so there were some doubts as to why it was appointed. The Committee had noted that the total contract for sanitation was worth R55 million, and had, in its report, recommended that IDT should be allowed to complete phase 1 but should be relieved of its task for the remaining phases. Sanitation, being one of the Millennium Development Goals, could not be delayed, and in rural areas and schools, the lack of sanitation was impinging not only on human dignity but also on health. In his address, the Minister highlighted that South Africa was not alone in facing challenges on sanitation as it was estimated that two billion people, worldwide, did not have access to sanitation. However, it was yet to be established exactly how many people required proper sanitation services in South Africa , meaning provision of proper bathrooms and toilets. Although he did not want to discuss the open toilet saga, he expressed his deep concern that this should ever have happened, and stressed that communities and councils should have acted far sooner to draw this to the attention of the authorities and ensure that something was done. A major challenge r', 'https://pmg.org.za/committee-meeting/13119/', 0),
    (13100, 'Human Settlements, Water and Sanitation', 91, '2011-06-21', 'National Treasury requirements for payments to service providers; Cooperative Housing, Whistle-Blowing policy, Development Finance Institutions'' merger: Department''s updates ', 'The Accountant General briefed the Committee on the requirements around payments to service providers, and in particular the issue of pre-payments to contractors. Section 7 of the Public Finance Management Act (PFMA) required National Treasury to prescribe a framework for cash management and this was done by way of the Treasury Regulations. Section 38 of the PFMA obliged Accounting Officers of State departments to ensure that a department (or entity) set up and maintained, effective, efficient and transparent systems of financial and risk management and internal control, and the Accounting Officer would be responsible for effective, efficient, economical and transparent use of the resources of the entity, and must take appropriate and effective steps to manage all working capital efficiently and economically. This involved not only collecting monies due, but also making payments when due, and ensuring that there was sufficient cash available to meet obligations, so that invoices were paid within 30 days of presentation. This would generally mean that pre-payments should not be made. However, in certain instances, Treasury Regulations allowed pre-payments, when this was arranged and recorded in a prior contract. However, it was stressed that it remained the responsibility of the Accounting Officer to ensure that this was not done if the risk of non-performance after payment was high, and if the goods or services were not provided, the Accounting Officer could be regarded as having made unauthorised, wasteful or fruitless expenditure, and be liable to be sanctioned, if he or she could not take immediate remedial action to ensure that the State did not suffer loss. It was stressed that Chapter 10 of the PFMA made it a criminal offence if an Accounting Officer, wilfully or negligently, failed to carry out his or her responsibilities. Ultimately, it would be up to Parliament to ensure that the provisions of the PFMA were followed, if the Executive failed to do so. Member', 'https://pmg.org.za/committee-meeting/13100/', 0),
    (13135, 'Human Settlements, Water and Sanitation', 91, '2011-06-27', 'Minister of Human Settlements on allegations concerning the National Home Builders Registration Council', 'The Minister of Human Settlements briefed the Committee on the status of the investigations into the alleged incidents of corruption and irregularities at the National Home Builders Registration Council. The allegations were investigated by the Special Investigations Unit and a report was submitted to the Minister. However, he found that the initial report contained a number of discrepancies and had referred the matter back to the Special Investigations Unit for further investigation. A subsequent allegation concerning the employment of a senior official of the Special Investigations Unit by the National Home Builders Registration Council was under investigation as well. The final report of the Special Investigations Unit would be made available to the Committee. The Board of the NHBRC had provided their full cooperation to the investigators. A major concern of the Department of Human Settlements was the significant number of housing units provided by the State that required repair because of shoddy construction. The estimated cost of rectification was R20 billion. Detailed statistical data was in the process of being compiled and would be made available in due course. The Committee was requested to review the NHBRC Act, which made provision for the Council to be both the regulator and to be responsible for carrying out repairs to faulty housing units. The Committee welcomed the commitment shown by the Minister in dealing with the matter. The allegations were first brought to the Minister’s attention by a Member of the Committee, who was protected in terms of the Rules of Parliament. However, subsequent developments had resulted in Members urging that other whistle-blowers were provided with adequate protection. Members asked if the officials concerned had declared their interests and signed the Code of Conduct. Members requested details of the plans to prevent future shoddy workmanship and to repair the existing faulty houses. Members queried the ability of the Ind', 'https://pmg.org.za/committee-meeting/13135/', 0),
    (13140, 'Human Settlements, Water and Sanitation', 91, '2011-06-28', 'Human Settlements Performance Plans 2011/12: Department & accredited municipalities', 'The National Department of Human Settlements gave a brief summary on the signing of the Intergovernmental Relations Protocol with metropolitan municipalities (metros) who would be receiving the Urban Settlement Development Grant (USDG). The relevant metros had undergone an accreditation process, which would be concluded by signature of a Memorandum of Understanding (MOU) between the Provincial governments and the metros, and Level 2 accreditation. Service Delivery Agreements would be concluded between the Minister of Human Settlements and the mayors. Although the agreements should all have been signed by 30 June, this had not been done, and the deadline could not be extended much past July. Members commented that they were disappointed that this seemed still to be in the planning stages, as the budgetary process had been concluded some time previously, and said that they would have expected delivery already to be taking place. However, this would be addressed in another forum. The City of Johannesburg , eThekwini Metro Municipality , City of Cape Town , the City of Tshwane and Nelson Mandela Bay Municipality (NMBM) briefed the Portfolio Committee on their Built Environment Performance Plans (BEPPs) which they had submitted as part of the process of assessment for approval for the Urban Settlements Development Grant (USDG) for metropolitan municipalities. The BEPP had to be a comprehensive built environment plan which included their Spatial Development and Built Environment Plan, their bulk infrastructure needs, transportation, economic and social development and their alignment to Outcome 8 on sustainable human settlement. They were required to indicate their Funding allocations, quantify their targets and identify their Deliverables and give a status update on their capacity and state of readiness for implementation The USDG was welcomed by all the metros and Members as, despite the fact that it may provide less actual money, it provided the metros with increased f', 'https://pmg.org.za/committee-meeting/13140/', 0),
    (13150, 'Human Settlements, Water and Sanitation', 91, '2011-06-30', 'Frances Baard, Ekurhuleni, Pixley Ka Seme, Mangaung & Buffalo City plans & projects 2011/12 ', 'The Committee continued to take briefings on the plans and projects for the 2011/12 financial year, from municipalities that had been accredited for housing delivery and would receive the Urban Settlement Development Grant (USDG). Briefings were given by Frances Baard, Ekurhuleni and Pixley Ka Seme, as well as Mangaung and Buffalo City . Each of these municipalities outlined their current situation in terms of demographics and housing development, what they were doing to achieve government Outcome 8 in relation to informal settlements and provision of housing, the plans for the built environment in their area, the challenges they faced and their project lists. They all reiterated the Chairperson’s comment that the USDG was well received and would assist municipalities to improve their Integrated Development Plan (Dips) and ensure that both provincial and municipal plans tied in more closely with each other, and to address funding issues. Ekurhuleni Municipality was intending to focus upon development around the airport “Aerotropolis” and noted that although it had not achieved upgrade of units in informal settlements and rental units, it had achieved compliance in access to basic water and refuse. It was linking transport networks. It had huge service delivery backlogs and said that it needed more funding, since its capital budget was mainly funded from Government grants and borrowings. Pixley Ka Seme District Municipality was located in the Northern Cape Province , and had a total population of 166 412, which represented 16.49% of the population of the Province. It consisted of eight category B municipalities, who generally had poor capacity. It had already begun the integration of housing units into its functions in 2006, and had a populated housing unit. It had received support from the national department, which was used for various projects as outlined. Although it was on a Housing Subsidy System, it indicated that this was unreliable. Frances Baard District Mu', 'https://pmg.org.za/committee-meeting/13150/', 0),
    (13210, 'Human Settlements, Water and Sanitation', 91, '2011-08-10', 'South Africa''s progress in implementing the eThekwini Commitments; Failure to deliver a country progress report for UNICEF''s Sanitation and Hygiene in Africa at a Glance : briefing by Department of Human Settlements', 'The Department of Human Settlements briefed Members on South Africa ''s progress on implementing the eThekwini Commitments. The First AfricaSan Conference held in 2002 aimed specifically at formulating a Millennium Development Goal for sanitation to reduce by half the number of people without access to basic sanitation and hygiene by 2015. The Second AfricaSan Conference held in Durban in 2008 assessed progress, challenges and lessons towards achieving the Goal for sanitation. Various African countries, including South Africa , made commitments. The eThekwini Commitments and the African Ministers'' Council on Water Declaration were detailed. Following eThekweni, Government had developed a South African Action Plan. The National Sanitation Task Team was established under the then Minister of Water Affairs and Forestry. The South African Sanitation and Hygiene Action Plan was later submitted to the African Ministers'' Council on Water. Progress on the Plan from 2008 to date was indicated. The National Sanitation Programme Unit was now under the Department of Human Settlements. This unit managed the National Sanitation Task Team and was to prepare the necessary progress reports. Although the Unit did not report progress to the African Ministers'' Council on Water due to poor reporting by role players, much had been achieved towards the implementation of the South African Sanitation and Hygiene Action Plan. The Department described in detail progress on the implementation of the eThekwini Commitments from 2008 to date. Progress in job creation and skills development training provided following the eThekwini Commitments was highlighted. Challenges included ineffective collaboration, non- alignment of sector plans, policies and strategies, dilapidating infrastructure and poor operations and maintenance, incompatible reporting system, sustainability of the current approved technologies, and inadequate health and hygiene promotion and user education. The South African Local Gov', 'https://pmg.org.za/committee-meeting/13210/', 0),
    (13236, 'Human Settlements, Water and Sanitation', 91, '2011-08-16', 'Parliament''s role in approval of international agreements: Workshop ', 'The Committee Section of Parliament, led by the Content Advisor to the Portfolio Committee on International Relations, briefed the Portfolio Committee on Human Settlements on the process for ratification of international agreements and treaties. South Africa had been an active member of the international community since 1994, and was a party to many bilateral and multilateral treaties. A “treaty” was defined as a binding instrument between states and / or international organisations, governed by international law, and treaties had to be in writing. They also had to be ratified by Parliament before becoming binding, as distinct from Ordinary Executive Agreements (OEAs), which were sub-agreements of a general nature, which became effective between the parties signing them, but were not necessarily binding on states. The Constitutional requirements of section 231 were described, which clearly set out that the signature of treaties and agreements was an Executive function, but the treaties needed approval from both houses of Parliament before they became binding on the State. Some treaties contained self-executing clauses, that did not require ratification or accession, and Members were cautioned to be on the look out for these. Other aspects that Members must consider were the type of approval sought, the fact that the treaty must comply with domestic law, the types of international obligations created, and financial and security implications. The National Assembly Rule 307(3) was also noted, in terms of which a portfolio committee must recommend approval or rejection, in writing, and it was explained that Section 75 and 76 Bills allowed for inclusion of concerns on domestication. The Committee asked, in particular, what would be required of this Committee in relation to the agreement between China and Mpumalanga Province , for an assisted housing project in Graskop. Members also asked if Parliament had the power to recommend amendments to provincial agreements, what t', 'https://pmg.org.za/committee-meeting/13236/', 0),
    (13276, 'Human Settlements, Water and Sanitation', 91, '2011-08-23', 'International relations commitments: Department of Human Settlements briefing ', 'Department of Human Settlements briefed Members on its international commitments and agreements. The Department had to serve the interest of the country through international advocacy and technical assistance. Some of the South African priorities of foreign policies were strengthening South-South and South-North co-operation, and consolidation of the African agenda. The Department had made agreements with, among other countries, Angola , China , Cuba , Denmark , and the Netherlands . It had also made an agreement with YouthBuild International in collaboration with the National Youth Development Agency and Habitat for Humanity in Gauteng . In this Agreement 176 young people had been trained in construction related skills and 100 units had been completed. The Department had participated in international debates and obtained a finer understanding of Human Settlement issues that did not rely on Northern perspectives and expertise. The Committee was really concerned about an agreement with China as Members found out that the houses were for sale and the Chinese brought their own material for building and were not prepared to transfer skills to South African citizens. The Committee also noted that most of the agreements were never tabled before Parliament. The Chairperson believed that the Department was not doing its job properly and that led to the Department not reporting sufficiently to the Committee.', 'https://pmg.org.za/committee-meeting/13276/', 0),
    (13335, 'Human Settlements, Water and Sanitation', 91, '2011-08-30', 'Department of Human Settlements  on 1st quarter 2011 peformance: briefing', 'The Department of Human Settlements reported on annual performance monitoring, overall Departmental performance, communication and outreach key, delivery Agreement - Outcome 8, job creation, accreditation of municipalities, turnaround strategy, entities performance, matters for action and redress, delivery performance, and financial issues. The Department had achieved 54% of approved targets on its annual performance plan monitoring during April – June 2011. Some of the key issues of communication and outreach were Budget Vote 2011/12 and Youth Build Limpopo where the Minister and Deputy Minister of Human Settlements and the Member of the Executive Council for Local Government and Housing, Limpopo , handed over, on 07 June 2011, 76 houses in commemoration of the 1976 youth. On Delivery Agreement Outcome 8, the Department noted the need for: improved technical support and capacity building to municipalities and provinces by the National Upgrading Support Programme; uniform norms and standards for basic services and human settlements service standards at municipal and provincial spheres - the Human Settlements & Basic Services Task Team was addressing this matter; policy approval, coordination and implementation at provincial and municipal spheres of higher densities; and to enhance development finance institution performances by picking institutions and associated product lines that performed exceptionally well and channelling additional funding and capacity towards these “ winners ” . The Technical Human Settlements Implementation Forum and Human Settlements Implementation Forum were convened and considered and approved the Programme of Action Reports for Outcome 8. The Department had developed a model to measure and report on job creation. The results of the model showed that the Department had created 14 868 direct jobs during the construction as well as 7 510 indirect jobs. Work of the National Accreditation Assessment Panel had commenced in various provinces and', 'https://pmg.org.za/committee-meeting/13335/', 0),
    (13350, 'Human Settlements, Water and Sanitation', 91, '2011-09-01', 'Social Housing Regulatory Authority (SHRA) on its regulations & accreditation of Social Housing Institutions; Committee Report on Kigali Conference', 'The Social Housing Regulatory Authority presented its Draft Regulations for the Social Housing Act as the Act stipulated that Parliament had to be consulted about the Regulations. The briefing first looked at the Social Housing Act, secondly, the accreditation of Social Housing Institutions, thirdly, it explained what accreditation meant, and lastly it dealt with the Regulations. In terms of the context, the Social Housing Act promulgated on 1 September 2009, established the Social Housing Regulatory Authority. The mandate of the SHRA was to invest in social housing and be able to regulate the sector. The vision was affordable rental homes in integrated urban environments through sustainable institutions. Its mission was to regulate and invest to deliver affordable rental homes and renew communities. SHRA aimed to interpret the Minister’s vision that people should be able to live, work, play and pray in their own areas, which implied social, economic and spatial restructuring. SHRA’s social housing projects embodied the vision of the Minister Structurally SHRA was divided into an Investment wing and a Regulation wing. SHRA had invested to date in 2 342 units (initial target 1 705), with a possible 1 500 still to come. There was huge interest from the private sector. Capacitation grants had been recommended. SHRA was engaging service providers for proposals and quotations. The 2011/12 accreditation cycle was complete. SHRA was preparing for the 2012/13 cycle. The Draft Regulations were ready for presentation to Parliament as required by the Act. The monitoring and evaluation of accredited Social Housing Institutions had started. The Auditor General evaluated SHRA after three months of operation and on the dashboard that represented the report graphically; it allocated only yellow and green faces. Yellow meant ‘ok’ and green meant excellent. There were no red faces, which would have indicated problems areas. The Act said that all institutions which have undertaken hou', 'https://pmg.org.za/committee-meeting/13350/', 0),
    (13374, 'Human Settlements, Water and Sanitation', 91, '2011-09-06', 'Social Housing Act regulations: briefing by Department of Human Settlements & Social Housing Regulatory Authority', 'The meeting entailed a read-through of the draft Regulations to the Social Housing Act (No16 of 2008) by the National Department of Human Settlements and the Social Housing Regulatory Authority - which had been established by the Act. The Act prescribed an obligatory consultation with Parliament on the regulations. The regulations set up criteria to regulate Social Housing Institutions. Only Social Housing Institutions which could prove sound management all round in terms of managing its finances, sustainability, with a code of conduct, and managing its buildings soundly, qualified for accreditation. One municipal Social Housing Institution had received full accreditation. The other social housing institutions that received full accreditation were private institutions. As the reading proceeded, inconsistencies emerged. One of these was that government as a whole promoted cooperatives, however the Social Housing Act did not really accommodate the structure, its method of operation or provide tenure options of cooperatives. The main objective of Social Housing was to provide affordable rental accommodation to low to middle income households. The emphasis was on rental accommodation. Cooperatives catered for the same target market, but the end result of the cooperative process was that the cooperative member owned his unit. This difference caused tension in how the cooperative model tried to fit into the existing provisions of social housing. A further complication that emerged was that municipal SHIs were Pty Ltd companies. Social Housing Institutions were, by law obliged to be non-profit organisations and independent from any other legal person, unless it was another Social Housing Institution of which it was a subsidiary. However, Municipal SHIs were Pty Ltd companies and not independent from municipalities. They were instrumental in developing and providing social housing in towns and cities in the country, and to prevent them from operating would be disastrous at ', 'https://pmg.org.za/committee-meeting/13374/', 0),
    (13401, 'Human Settlements, Water and Sanitation', 91, '2011-09-13', 'Social Housing Regulatory Authority Regulations: public comments received by the Department of Human Settlements: consideration; Report on Overview of Municipal Presentations ', 'Members proposed requesting the Legal Unit to advise the Committee on legal issues pertaining to the Social Housing Regulations. The report from the parliamentary Research Unit was to be analysed as it would assist the Committee ahead of the meeting with the provincial department in Bloemfontein the following day. The Committee would then deliberate on the Regulations proposed by the Social Housing Regulatory Authority and the Department. There seemed to be some confusion in this regard as it appeared that the Department had effected the changes after public hearings. The Chairperson observed that the “new” document did not speak to the public comments. Members said that in order for regulations to be effective they needed to be implemented to ascertain their effectiveness. The present documents looked completely different from those used at the previous meeting. Therefore it was suggested that the Members give themselves time to study both documents and when the Committee reconvened identify all the public comments which would be used while the Department would come to answer questions on discrepancies. The Committee was advised that it should not find itself in a situation where amendments to the Act were introduced through the back door. The focal point was to amend the regulations. The Chairperson suggested that the Committee continue going through the documents. Members detected that a new section had been inserted and headings were switched around without any notification being made on the new documents; they felt that “wool is being put over our eyes”. There appeared to be numerous changes to Section 2 as some items were taken out and new items inserted without any reflection and sentences worded to give an opposite meaning. The Chairperson observed that the Social Housing Regulatory Authority had been quick to respond that it had picked up on the issues but what it had done was effect insertions without Members'' knowledge. Members observed that the Regulatio', 'https://pmg.org.za/committee-meeting/13401/', 0),
    (13451, 'Human Settlements, Water and Sanitation', 91, '2011-10-10', 'Department of Human Settlements 2010/11 Annual Report: recommendations by Auditor-General & Financial and Fiscal Commission ', 'The Office of the Auditor-General noted that the NDHS had received an ‘unqualified opinion with other matters’ since 2007/08 up until the present year under review 2010/11. Emphasis of matters in the current audit opinion centred on four issues: uncertainty due to litigation the department was involved in, irregular expenditure, the restatement of corresponding figures and under-expenditure by the department. The Auditor-General highlighted a number of instances where the NDHS contravened the Public Finance Management Act and the Division of Revenue Act. Vacancies in key management positions had been filled during the period under review. The goal was to achieve an unqualified audit opinion without matters, so that the focus could move towards the auditing of predetermined objectives and service delivery items. Members asked what unaudited supplementary schedules were; what happened when departments did not disclose their irregular expenditure; whether accounting officers who contravened the Division of Revenue Act were not aware of its legally required procedures; whether the AG looked at the vacancy rate when it audited a department and if it audited for actual performance against performance agreements for officials. Mention was made of R20 million owed to the NDHS by a developer. To date the money had not been recovered. Whose duty was it to recoup the money, the national accounting officer of the NDHS, or the provincial accounting officer of the province in which it happened? The Financial and Fiscal Commission explained that it made recommendations on the equitable division of nationally raised revenue among and between the three spheres of government and on any other fiscal matters. Its presentation highlighted selected NDHS strategic objectives for 2010/11. Firstly, its target was to deliver 220 000 housing units per annum but actual delivery was 121 879 units yet the NDHS had spent 98.8% of its allocated budget. It also aimed to facilitate 80 000 affordable', 'https://pmg.org.za/committee-meeting/13451/', 0),
    (13478, 'Human Settlements, Water and Sanitation', 91, '2011-10-11', 'Annual Reports 2010/11: Department Human Settlements, Social Housing Regulatory Authority, Housing Development Agency, NURCHA, Rural Housing Loan Fund, National Home Builders Regulatory Council, National Housing Finance Corporation', 'The Department of Human Settlements and various entities presented the Annual Report and performance reports for 2010/11. The Department of Human Settlements (DHS) received an unqualified audit report, although there were some matters of emphasis, to which it was giving attention. The Department had undertaken some restructuring following the broadened mandate, and although there were various vacancies, it had taken the strategic decision not to fill them at present, pending a finalisation of the new organogram. There were 860 acknowledgements of debt entered into, to the value of R8.2 million with municipal employees, in relation to fraud on subsidy programmes. During this period it was noted that eight municipalities had been recommended for accreditation. Other highlights were the recapitalisation of NURCHA to the value of R300 million, and a cash injection of R49.5 million to the Rural Housing Loan Fund. The Human Settlement Development Grant took 93.4% of the entire R16 billion, and was transferred to the provinces in terms of the Division of Revenue Act. Monitoring and evaluation was done on 285 projects. Detailed work was done on informal settlements and a further report would be presented. There were challenges around projects to which the DHS allocated funds, but could not oversee, and where certain competencies, such as servicing of sites, lay within the competence of municipalities. The Department also needed to improve on data collection and allocation of resources to provinces. A unit at national level would link the performance of human settlements to all its entities and provinces. Training of staff must also be addressed. Members hoped the turnaround would not lead to retrenchments, urged better reporting mechanisms, asked about use of consultants and travel expenses, and sanctions against those guilty of corruption. They questioned the terms of learnerships, and asked for more information on the hostels, the provinces getting grants, details of Thub', 'https://pmg.org.za/committee-meeting/13478/', 0),
    (13571, 'Human Settlements, Water and Sanitation', 91, '2011-10-18', 'Human Settlements Budgetary Review and Recommendation Report 2011: discussion', 'The Committee met to consider the adoption the Budgetary Review and Recommendation Report 2011. Members queried the accuracy and validity of the figures given in the report. Members also expressed disappointment at the failure of the Department to provide them with the turnaround strategy report. Numerous inconsistencies where highlighted between the Budgetary Review and Recommendation Report 2011 and that of the Annual report. This led to suggestions by the Members that the Department should make use of consultants when coming up with their reports. Failure by the Department to finalise strategies like the Framework for Human Settlement Planning and Informal Settlement Strategy was noted to the Department’s greatest non achievement. Members made numerous grammatical changes. Members also expressed concern at the Department’s citing of policy that had not yet been approved. The report was not adopted as the Committee wanted to clarify certain information in the next meeting with the Presidency. The Chairperson had consulted with the Parliamentary Legal Unit regarding the issue of unauthorized expenditure by the Free State Provincial Department of Cooperative Governance, Traditional Affairs and Human Settlements. The letter read that according to the research brief given to the Legal Unit, the Department concerned, had incurred expenditure not approved in the Business Plans submitted for the 2010/11 and 2011/12 allocation of the Human Settlement Development Grant.', 'https://pmg.org.za/committee-meeting/13571/', 0),
    (13594, 'Human Settlements, Water and Sanitation', 91, '2011-10-19', 'Department of Human Settlements performance towards achieving Outcome 8: by Department of Performance Monitoring & Evaluation', 'The Department of Performance Monitoring, Evaluation and Administration (DPME) presented its report on progress made by the Department of Human Settlements towards the achievement of Outcome 8 of the government’s outcomes-based approach adopted in 2010 which focused on “integrated human settlements” and aimed towards “sustainable human settlements and improved quality of household life”. The upgrading of 400 000 households in informal settlements with access to secure tenure and basic services was on track but the government’s aim of providing 80 000 well-located rental units by 2014 was proceeding slower than targeted. It was reported that, as of March 2011, 95% of households had access to basic water while 82% had access to basic sanitation. Three of the six targets under the sub-output “Improved affordable property market”, including the development and implementation of a Mortgage Default Insurance Scheme, were reported as being substantially behind timelines and requiring urgent intervention. A number of members expressed their concern that the Department of Performance Monitoring, Evaluation and Administration’s report seemed to be based on the paper report of the Department of Human Settlements and not on what was happening on the ground. Members asked how it had arrived at statistics such as the one reporting that 82% of households had access basic sanitation. The Committee was not satisfied that these statistics on basic service delivery achieved as of March 2011 reflected the true situation of what was happening on the ground. In particular, members asked what was being done about the unsatisfactory delivery of basic sanitation. A member asked how regularly the new “management performance assessments” of national and provincial departments, due to begin in November 2011, would be conducted. One member opined that there were a number of overlaps in the mandates of the Housing Development Agency, the National Planning Commission and the DPME and asked if the', 'https://pmg.org.za/committee-meeting/13594/', 0),
    (13625, 'Human Settlements, Water and Sanitation', 91, '2011-10-25', 'Servcon on its 2010/11 Annual Report; Social Housing Act Regulations; Rental Housing Act Amendments ', 'Committee members were taken through changes made to the draft Social Housing Act Regulations. These changes were based on consultations held with the Committee as well as the South African Housing Cooperatives Association. Many changes were technical and involved the repositioning of clauses under their correct chapters. Sub-clauses 3(3)(a) and(b) under Chapter 2: Applications, qualifying criteria, accreditation were amended so as to be in line with the new Companies Act 2008. Changes made to Chapter 5: Investment Criteria were the inclusion of words such “levies” and “memberships” so as to ensure that the Regulations included terminology specific to housing co-operatives. One member asked for clarity on the inserted definition of “occupancy agreement”. Also if, in relation to sub-clause 23(4), the National Department of Human Settlements saw a reason for the current Housing Act to be amended. Further, was there a limit on the number of subsidiary companies that could register under a social housing institution? One member suggested that the provision requiring social housing institutions to insure their stock should be more specific about which type of insurance was required. The legal advisor in the National Department of Human Settlements presented members with an “introduction” to proposed amendments to the Rental Housing Act of 1999. The amendments addressed various implementation, legal and administrative issues experienced by the Rental Housing Tribunal and provinces since the inception of the Act; made the establishment of the Rental Housing Tribunals in every province mandatory; and further sought to empower the Tribunals to rescind any of its rulings. Members asked if there was any provision for legal action to be taken against provinces that had failed to establish Rental Housing Tribunals; why not more than two members of a Rental Housing Tribunal should be legally qualified and whether this was practical; if the ability of a Rental Housing Tribunal to ', 'https://pmg.org.za/committee-meeting/13625/', 0),
    (13688, 'Human Settlements, Water and Sanitation', 91, '2011-11-01', 'Social Housing Regulatory Authority Regulations: adoption', 'The Committee firstly discussed the draft of the regulations in terms of the Social Housing Act of 2008, and isolated some questions that should be put to the legal advisors. Members were concerned about the 90-day period allowed for the applications, wondering if this should not be shorter, and also wondering if this included the appeal process, should an application be turned down. The State Law Advisors and Departmental officials noted that this time period correlated with the Promotion of Administrative Justice and Promotion of Access to Information Act requirements, and explained how these linked to the Social Housing Act. The Committee agreed not to change the time period. Members also asked about the reason why profits of municipal entities were mentioned, wondering if the entities could be excluded from complying with qualifying criteria, asked what had happened to funds controlled formerly by provincial housing boards, and received clarity on the fact that state owned entities, including municipal entities, could not distribute their profits. The references to an independent Chairperson were clarified. Members raised queries on the internal and external audit processes, and noted that stern controls must be exercised over housing matters. They questioned the meaning of “affected” by HIV. Members also questioned why the wording did not refer directly to the number of units, and were informed of the distinction between rentals and levies. Members also said that it was necessary to define matters more clearly in this legislation, although the entities may well be defined in other legislation. The Department explained what a tenant membership agreement entailed, and the time limits and considerations around transfer of social housing stock. Members finally asked what was being done to communicate and educate the public on the new regulations. Members adopted the Regulations.', 'https://pmg.org.za/committee-meeting/13688/', 0),
    (13711, 'Human Settlements, Water and Sanitation', 91, '2011-11-08', 'Department of Human Settlements on its Turnaround Strategy, progress with Rural Household Infrastructure Programme, and Audit Report ', 'The Department of Human Settlements presented its progress report on its Turnaround Strategy which had been approved by its Minister but still needed to be signed off by the Minister of Public Service and Administration. Outstanding matters included the migration of staff, an adequate human resource plan, recruitment for the new posts, ongoing training and development initiatives and the implementation of a Change Management programme which involved culture change, performance management and a monitoring and evaluation system. Members requested clarity on the proposed structure of the Department as many Members were concerned that the structure was not as “lean” as the Department professed it to be and a number of proposed Chief Directorates, such as “Capacity to Change” and “Capacity Development”, seemed to overlap. A more comprehensive document would be circulated to the Committee. Was the restructuring of the Department based purely on its new additional mandate to deliver sanitation services. Members again complained that the Department’s progress was not measurable. Members asked if NDHS was sure the necessary skills would be directed to the correct functions so the realignment would translate into better service delivery. The Department presented its progress with the Rural Housing Infrastructure Programme, including its consideration of previous recommendations by the Portfolio Committee. National Treasury had allocated a budget of R1.2 billion for the provision of basic sanitation and some water projects in rural communities and the Department was currently in Phase 2 of the Programme. Progress had been slow in some areas because some contracts had had to be terminated and new ones signed. The NDHS had only spent approximately 10% of its budget for the current financial year. The NDHS had considered the Committee’s recommendations but had decided not to seek legal opinion about terminating the contract with the Independent Development Trust as recommended by', 'https://pmg.org.za/committee-meeting/13711/', 0),
    (13730, 'Human Settlements, Water and Sanitation', 91, '2011-11-10', 'Rental Amendment Bill: Departmental briefing ', 'The Department of Human Settlements presented the Rental Housing Amendment Bill (the Bill) to the Committee. At the outset, the Chairperson expressed concern that this Bill had missed the June deadline for submission and insisted that the Department must, in future, provide the Committee with its schedule of legislation, to allow for proper planning. The Department explained that the main reason for the Bill was to address legislative and administrative issues around the Rental Housing Tribunal (RHT). This Bill now made it mandatory for all provinces to establish a Rental Housing Tribunal, as they all now had rental housing stock, instead of the position where this was optional, in the past, and also sought to establish a uniform structure for all Tribunals, which would in future be governed by nationally-drawn regulations. The Bill also made provision for the Tribunals, in future, to be able to rescind rulings that had been made in error. It provided rules for the composition of tribunals, which were to consist of six members, with two of them legally-qualified, and also set out that no member could serve more than two consecutive terms. Certain definitions and wording were being amended in the original Act to bring them in line with other legislation. The Department indicated that the consultation process had been conducted in the previous year and some of the suggestions had been incorporated into the Bill. The sessions had been attended by provincial Legislatures, provincial governments, provincial RHTs and private stakeholders, and National Economic Development and Labour Council processes were followed. Members asked what would happen to the provincial regulations already made, enquired as to the feedback from the public hearings, asked if the same restrictions on terms of office would apply to the legally qualified members, and asked if it would be possible for local magistrates and magistrates courts to be used where municipal offices were far distant from t', 'https://pmg.org.za/committee-meeting/13730/', 0),
    (13757, 'Human Settlements, Water and Sanitation', 91, '2011-11-15', 'Sanitation and the Rural Housing Infrastructure Programme: Departmental update briefings', 'The Chairperson said that this meeting had initially been called to deal with the turnaround strategy of the Department of Human Settlements (DHS), but there had been some misunderstanding in communication, and this report would be provided in future. Instead, the DHS would answer questions raised in a previous meeting in relation to the Rural Housing Infrastructure Programme (RHIP) and sanitation issues. A Member questioned why DHS had waited for the Committee to remind it of details required, saying that officials taking notes in the meeting should have provided feedback to the Director General, who should have taken the initiative to give the feedback. However, the Chairperson clarified the position in this instance, and did not anticipate problems in future. The DHS then gave an update report on the RHIP, saying that it was largely dependent upon input from the Independent Development Trust (IDT), a state entity contracted by the DHS to assist with the implementation. The contract with IDT stipulated that it would be allocated R415 million to construct 53 000 units over a three year period. However, the DHS had been advised to tell IDT that it should first complete phase 1 and finalise the backlog before receiving any further allocations. More money was released in July. The DHS noted that although it was not entirely satisfied with the performance of IDT, but noted that many of the delays had arisen because the IDT was heavily engaged with community liaison. The IDT had delivered 1 574 units, against the target of 16 870, for the year. The DHS asked that the Committee afford it enough time to receive the Quantity Surveyor reports on outputs, and to consider the technical and legal issues that required correction, as also to consider its next actions. The DHS conceded that not all consultations in respect of the sanitation programme were properly done. Members wanted to know why IDT was given another substantial allocation, despite continually failing to deliver', 'https://pmg.org.za/committee-meeting/13757/', 0)
ON CONFLICT (pmg_meeting_id) DO NOTHING;

COMMIT;
